function normalizedWaterSubtype(place: Pick<OsmPoi, 'type' | 'subtype'> & Record<string, any>) {
  if (String(place.type || '') !== 'water') return '';
  const subtype = String(place.subtype || '').toLowerCase().replace(/[\s-]+/g, '_');
  if (subtype === 'tap' || subtype === 'drinking_water' || subtype === 'water_point' || subtype === 'fountain') return 'water';
  if (subtype === 'spring') return 'water';
  if (WATER_PLACE_FILTER_IDS.has(subtype)) return subtype;
  return 'shore_access';
}

function placeMatchesFilterId(place: OsmPoi, filterId: string) {
  if (String(place.type || '') !== 'water') {
    return place.type === filterId || (CAMP_PLACE_TYPES.has(String(place.type || '')) && filterId === 'camping');
  }
  const subtype = normalizedWaterSubtype(place);
  if (filterId === 'water') return true;
  return subtype === filterId;
}

function placeMatchesFilters(place: OsmPoi, filters: Set<string>) {
  if (String(place.type || '') !== 'water') {
    return filters.has(place.type || 'poi') || (CAMP_PLACE_TYPES.has(String(place.type || '')) && filters.has('camping'));
  }
  const subtype = normalizedWaterSubtype(place);
  return filters.has('water') || filters.has(subtype);
}

function categoryForPlaceFilter(filterId: string) {
  return WATER_PLACE_FILTER_IDS.has(filterId) ? 'water' : filterId;
}

type ScopedMapSearchIntent = {
  query: string;
  whatText: string;
  whereText: string;
  categoryIds: string[];
  categories: string;
  categoryLabel: string;
  radiusMi: number;
};

type ScopedMapSearchSession = {
  id: string;
  query: string;
  categoryLabel: string;
  categories: string;
  center: { lat: number; lng: number; name: string };
  places: OsmPoi[];
  loading: boolean;
  error?: string;
  startedAt: number;
};

type ScopedSearchCategoryRule = {
  label: string;
  ids: string[];
  radiusMi?: number;
  pattern: RegExp;
};

const SCOPED_SEARCH_SPLIT_RE = /\s+(near|nearby|around|by|close to|in|at)\s+/i;
const SCOPED_SEARCH_CURRENT_LOCATION_RE = /^(me|my location|current location|here|near me)$/i;
const SCOPED_SEARCH_PREFIX_RE = /^(gas stations?|gas|fuel|petrol|diesel|propane|restaurants?|food|coffee|groceries|grocery|campgrounds?|camps?|camping|rv parks?|lodging|hotels?|motels?|trailheads?|trails?|treks?|hikes?|views?|viewpoints?|waterfalls?|falls|glaciers?|parks?|attractions?|mechanics?|repair|parking|medical|pharmacy|wifi)\s+(.{2,})$/i;

const SCOPED_SEARCH_CATEGORY_RULES: ScopedSearchCategoryRule[] = [
  { label: 'Fuel', ids: ['fuel'], radiusMi: 18, pattern: /\b(gas stations?|gas\b|fuel|petrol|diesel|charging stations?|ev charging)\b/i },
  { label: 'Propane', ids: ['propane'], radiusMi: 18, pattern: /\b(propane|lp gas|lpg)\b/i },
  { label: 'Food', ids: ['food'], radiusMi: 16, pattern: /\b(restaurants?|food|dinner|lunch|breakfast|cafe|coffee|pizza|tacos?)\b/i },
  { label: 'Groceries', ids: ['grocery'], radiusMi: 18, pattern: /\b(grocer(?:y|ies)|market|supermarket|supplies)\b/i },
  { label: 'Camps', ids: ['camping'], radiusMi: 28, pattern: /\b(campgrounds?|campsites?|camps?|camping|rv parks?|rv sites?)\b/i },
  { label: 'Lodging', ids: ['lodging'], radiusMi: 22, pattern: /\b(lodging|hotels?|motels?|inns?|cabins?|hostels?)\b/i },
  { label: 'Trails', ids: ['trailhead'], radiusMi: 30, pattern: /\b(trailheads?|trails?|treks?|hikes?|hiking|routes?)\b/i },
  { label: 'Views', ids: ['viewpoint'], radiusMi: 28, pattern: /\b(views?|viewpoints?|overlooks?|lookouts?|scenic)\b/i },
  { label: 'Waterfalls', ids: ['water', 'viewpoint', 'attraction'], radiusMi: 32, pattern: /\b(waterfalls?|falls|cascade)\b/i },
  { label: 'Glaciers', ids: ['glacier', 'viewpoint', 'attraction'], radiusMi: 40, pattern: /\b(glaciers?|icefields?)\b/i },
  { label: 'Parks', ids: ['park'], radiusMi: 35, pattern: /\b(parks?|national parks?|state parks?)\b/i },
  { label: 'Attractions', ids: ['attraction', 'historic', 'park'], radiusMi: 30, pattern: /\b(attractions?|things to do|monuments?|historic|museums?)\b/i },
  { label: 'Mechanic', ids: ['mechanic', 'parts'], radiusMi: 22, pattern: /\b(mechanics?|repair|auto repair|parts|service shop)\b/i },
  { label: 'Parking', ids: ['parking'], radiusMi: 14, pattern: /\b(parking|trail parking|lot)\b/i },
  { label: 'Medical', ids: ['medical'], radiusMi: 22, pattern: /\b(medical|hospital|clinic|pharmacy|urgent care)\b/i },
  { label: 'Wifi', ids: ['wifi'], radiusMi: 16, pattern: /\b(wifi|internet|cell service)\b/i },
];

function normalizeScopedSearchText(value: string) {
  return String(value || '').trim().replace(/\s+/g, ' ');
}

function scopedSearchCategoryForText(text: string): Pick<ScopedMapSearchIntent, 'categoryIds' | 'categories' | 'categoryLabel' | 'radiusMi'> | null {
  const clean = normalizeScopedSearchText(text);
  if (!clean) return null;
  const rule = SCOPED_SEARCH_CATEGORY_RULES.find(item => item.pattern.test(clean));
  if (!rule) return null;
  const categoryIds = Array.from(new Set(rule.ids));
  const categories = Array.from(new Set(categoryIds.map(categoryForPlaceFilter))).join(',');
  return {
    categoryIds,
    categories,
    categoryLabel: rule.label,
    radiusMi: rule.radiusMi ?? 25,
  };
}

function parseScopedMapSearchQuery(query: string): ScopedMapSearchIntent | null {
  const cleanQuery = normalizeScopedSearchText(query);
  if (cleanQuery.length < 4) return null;

  const splitMatch = cleanQuery.match(SCOPED_SEARCH_SPLIT_RE);
  if (splitMatch?.index != null) {
    const whatText = normalizeScopedSearchText(cleanQuery.slice(0, splitMatch.index));
    const whereText = normalizeScopedSearchText(cleanQuery.slice(splitMatch.index + splitMatch[0].length));
    const category = scopedSearchCategoryForText(whatText);
    if (category && whereText.length >= 2) {
      return { query: cleanQuery, whatText, whereText, ...category };
    }
  }

  const prefixMatch = cleanQuery.match(SCOPED_SEARCH_PREFIX_RE);
  if (prefixMatch) {
    const whatText = normalizeScopedSearchText(prefixMatch[1]);
    const whereText = normalizeScopedSearchText(prefixMatch[2]);
    const category = scopedSearchCategoryForText(whatText);
    if (category && whereText.length >= 2) {
      return { query: cleanQuery, whatText, whereText, ...category };
    }
  }
  return null;
}

function scopedSearchPlaceKey(place: Pick<OsmPoi, 'id' | 'name' | 'lat' | 'lng' | 'type'>) {
  return String(place.id || `${place.type || 'poi'}:${place.name || 'place'}:${Number(place.lat).toFixed(5)}:${Number(place.lng).toFixed(5)}`);
}

function normalizeScopedSearchPoi(place: Partial<OsmPoi>, index: number, sessionId: string, center: { lat: number; lng: number }): OsmPoi | null {
  const lat = Number(place.lat);
  const lng = Number(place.lng);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return null;
  const rawType = String(place.type || place.subtype || 'poi').toLowerCase().replace(/[^a-z0-9_]+/g, '_') || 'poi';
  const type = ({
    gas: 'fuel',
    gas_station: 'fuel',
    fuel_station: 'fuel',
    petrol: 'fuel',
    ev_charging: 'fuel',
    charging_station: 'fuel',
    restaurant: 'food',
    cafe: 'food',
    coffee: 'food',
    fast_food: 'food',
    supermarket: 'grocery',
    market: 'grocery',
    hotel: 'lodging',
    motel: 'lodging',
    hostel: 'lodging',
    waterfall: 'attraction',
    falls: 'attraction',
    park: 'attraction',
  }[rawType] || rawType) as OsmPoi['type'];
  const name = normalizeScopedSearchText(String(place.name || cleanDisplayLabel(type) || 'Place'));
  const distanceMi = Number.isFinite(Number(place.distance_mi))
    ? Number(place.distance_mi)
    : haversineKm(center.lat, center.lng, lat, lng) * 0.621371;
  return {
    ...(place as OsmPoi),
    id: String(place.id || place.place_id || place.provider_place_id || `scoped:${sessionId}:${index}:${lat.toFixed(5)}:${lng.toFixed(5)}`),
    name,
    lat,
    lng,
    type,
    source: place.source || 'trailhead_search',
    source_label: place.source_label || place.source_badge || 'Map search',
    distance_mi: Number.isFinite(distanceMi) ? Math.round(distanceMi * 10) / 10 : undefined,
  };
}

function scopedPoiToSearchPlace(poi: OsmPoi, query: string): SearchPlace {
  return {
    ...(poi as unknown as SearchPlace),
    id: poi.id,
    name: poi.name,
    lat: poi.lat,
    lng: poi.lng,
    type: poi.type || 'poi',
    source: poi.source || 'trailhead_search',
    source_label: poi.source_label || poi.source_badge || 'Map search',
    geocode_query: query,
  };
}

function scopedPoiIconName(type?: string): keyof typeof Ionicons.glyphMap {
  switch (String(type || '').toLowerCase()) {
    case 'fuel': return 'flash-outline';
    case 'propane': return 'flame-outline';
    case 'food': return 'restaurant-outline';
    case 'grocery': return 'cart-outline';
    case 'camp':
    case 'camping': return 'bonfire-outline';
    case 'lodging': return 'bed-outline';
    case 'trail':
    case 'trailhead': return 'trail-sign-outline';
    case 'viewpoint': return 'flag-outline';
    case 'glacier': return 'snow-outline';
    case 'water': return 'water-outline';
    case 'mechanic':
    case 'parts': return 'construct-outline';
    case 'parking': return 'car-outline';
    case 'medical': return 'medical-outline';
    case 'wifi': return 'wifi-outline';
    default: return 'location-outline';
  }
}

function waterKindLabel(kind?: string): string {
  switch (String(kind || '').toLowerCase()) {
    case 'river': return 'River';
    case 'stream': return 'Stream';
    case 'canal': return 'Canal';
    case 'reservoir': return 'Reservoir';
    case 'lake': return 'Lake';
    default: return 'Waterbody';
  }
}

function isLakeOfTheWoods(lat: number, lng: number, name?: string) {
  const text = String(name || '').toLowerCase();
  return text.includes('lake of the woods') || text.includes('lac des bois') || (lat >= 48.35 && lat <= 49.55 && lng >= -95.65 && lng <= -93.35);
}

function isLikelyCanadianWater(lat: number, lng: number, name?: string) {
  if (isLakeOfTheWoods(lat, lng, name)) return true;
  if (lng >= -141.5 && lng <= -52 && lat >= 49) return true;
  if (lng >= -67.5 && lng <= -52 && lat >= 43) return true;
  return false;
}

function waterChartContext(lat: number, lng: number, name?: string) {
  if (isLikelyCanadianWater(lat, lng, name)) {
    return {
      chart_source: 'CHS NONNA bathymetry (non-navigational) for Canadian waters; Lake of the Woods also has CHS chart 6201 official chart context.',
      chart_url: 'https://www.chs.gc.ca/data-gestion/nonna/index-eng.html',
      safety_url: 'https://tc.canada.ca/en/marine-transportation/marine-safety/boating-safety',
      navigation_note: 'NONNA bathymetry is not for navigation. Verify with official CHS charts, local markers, water levels, weather, and required safety gear before boating.',
    };
  }
  return {
    chart_source: 'NOAA chart layer where coverage exists; many inland lakes may not have charted depth or hazard data.',
    chart_url: 'https://www.nauticalcharts.noaa.gov/charts/noaa-enc.html',
    safety_url: 'https://www.uscgboating.org/',
    navigation_note: 'Waterbody context only. Use the NOAA chart layer where available for depth soundings, channels, aids, and hazards; check NWS alerts, water levels, local closures, required safety gear, and official charts before boating.',
  };
}

function mapWaterbodyPlace(lat: number, lng: number, name?: string, kind?: string): OsmPoi {
  const waterbodyType = String(kind || '').toLowerCase() || 'waterbody';
  const cleanName = cleanDisplayLabel(String(name || waterKindLabel(waterbodyType)));
  const chart = waterChartContext(lat, lng, cleanName);
  return {
    id: `map_water_${lat.toFixed(5)}_${lng.toFixed(5)}`,
    name: cleanName,
    lat,
    lng,
    type: 'water',
    category: 'water',
    subtype: waterbodyType,
    source: 'map_waterbody',
    source_label: 'Map waterbody',
    source_badge: 'Map waterbody',
    source_freshness: 'Base map water feature. Depths, channels, hazards, and access rules require official/current sources.',
    waterbody_name: cleanName,
    waterbody_type: waterbodyType,
    access: 'see nearby access points',
    craft: 'verify local restrictions',
    fishing_score_label: 'Unknown fishing quality',
    chart_source: chart.chart_source,
    chart_url: chart.chart_url,
    weather_url: `https://forecast.weather.gov/MapClick.php?lat=${lat.toFixed(5)}&lon=${lng.toFixed(5)}`,
    tides_url: 'https://tidesandcurrents.noaa.gov/',
    safety_url: chart.safety_url,
    navigation_note: chart.navigation_note,
  } as OsmPoi;
}

function mapWaterNavigationPlace(props: Record<string, any>, lat: number, lng: number): OsmPoi {
  const subtype = String(props.subtype || props.kind || 'navigation_aid').toLowerCase();
  const name = cleanDisplayLabel(String(props.name || props.label || props.navigation_feature || 'Water navigation point'));
  const chart = waterChartContext(lat, lng, name);
  const isHazard = subtype === 'water_hazard';
  return {
    id: String(props.id || `map_water_nav_${lat.toFixed(5)}_${lng.toFixed(5)}`),
    name,
    lat,
    lng,
    type: 'water',
    category: 'water',
    subtype,
    source: 'openseamap',
    source_label: String(props.source || 'OpenStreetMap / OpenSeaMap'),
    source_badge: 'OpenSeaMap / OSM',
    source_freshness: String(props.source_freshness || 'Open seamark data; verify against official charts and local markers.'),
    waterbody_name: name,
    waterbody_type: 'navigation',
    access: 'verify locally',
    craft: 'boating context',
    fishing_score_label: 'Navigation context',
    chart_source: chart.chart_source,
    chart_url: chart.chart_url,
    weather_url: `https://forecast.weather.gov/MapClick.php?lat=${lat.toFixed(5)}&lon=${lng.toFixed(5)}`,
    tides_url: 'https://tidesandcurrents.noaa.gov/',
    safety_url: chart.safety_url,
    navigation_feature: cleanDisplayLabel(String(props.navigation_feature || props.label || props.seamark_type || subtype)),
    hazard_type: cleanDisplayLabel(String(props.hazard_type || (isHazard ? props.seamark_type || subtype : ''))),
    mark_color: cleanDisplayLabel(String(props.mark_color || props.marker_color || '')),
    mark_shape: cleanDisplayLabel(String(props.mark_shape || '')),
    light_character: cleanDisplayLabel(String(props.light_character || '')),
    depth_ft: Number.isFinite(Number(props.depth_ft)) ? Number(props.depth_ft) : undefined,
    max_draft_ft: Number.isFinite(Number(props.max_draft_ft)) ? Number(props.max_draft_ft) : undefined,
    navigation_note: String(props.navigation_note || 'Open seamark data only. Use official charts, local markers, water levels, weather, and required safety gear before boating.'),
  } as OsmPoi;
}

