const MAP_MODE_PRESET_IDS = new Set<MapModePresetId>(MAP_MODE_PRESETS.map(preset => preset.id));
function validMapModePreset(value: unknown): MapModePresetId | null {
  const candidate = String(value || '') as MapModePresetId;
  return MAP_MODE_PRESET_IDS.has(candidate) ? candidate : null;
}

type CommunityPinTypeId = typeof COMMUNITY_PIN_TYPES[number]['id'];
function communityPinMeta(type?: string) {
  return COMMUNITY_PIN_TYPES.find(t => t.id === type) ?? COMMUNITY_PIN_TYPES[COMMUNITY_PIN_TYPES.length - 1];
}

function normalizedCopilotPinType(type?: unknown): CommunityPinTypeId {
  const clean = String(type || '').toLowerCase().replace(/[\s-]+/g, '_');
  const aliases: Record<string, CommunityPinTypeId> = {
    campsite: 'camp',
    camping: 'camp',
    gas: 'fuel',
    poi: 'attraction',
    point_of_interest: 'attraction',
    note: 'trail_note',
    road: 'road_report',
    hazard: 'warning',
  };
  const candidate = aliases[clean] ?? clean;
  return COMMUNITY_PIN_TYPES.some(t => t.id === candidate) ? candidate as CommunityPinTypeId : 'other';
}

function normalizedCommunityPinType(pin: Pick<Pin, 'type' | 'description'>): string {
  const type = (pin.type || 'other').toLowerCase();
  if (type === 'gpx_import') return 'gpx_import';
  if (type === 'other' && /imported from gpx/i.test(pin.description || '')) return 'gpx_import';
  return type;
}

function validIds(values: unknown, allowed: readonly string[]) {
  if (!Array.isArray(values)) return null;
  const allowedSet = new Set(allowed);
  return values.filter((value): value is string => typeof value === 'string' && allowedSet.has(value));
}

function validMapLayer(value: unknown): MapLayer | null {
  return value === 'satellite'
    || value === 'topo'
    || value === 'hybrid'
    || value === 'light'
    || value === 'city'
    || value === 'contrast'
    || value === 'desert'
    || value === 'snow'
    || value === 'dark'
    || value === 'red'
    || value === 'extreme'
    ? value
    : null;
}

