  async function openCampInsight(camp: CampsitePin, detail?: CampsiteDetail | null): Promise<boolean> {
    setLoadingInsight(true);
    setLoadingWiki(true);
    try {
      const insight = await api.getCampsiteInsight({ name: camp.name, lat: camp.lat, lng: camp.lng,
        description: camp.description, land_type: camp.land_type,
        amenities: detail?.amenities ?? [], facility_id: camp.id ?? '' });
      if (selectedCampRef.current?.id !== camp.id) {
        setLoadingWiki(false);
        return false;
      }
      setCampInsight(insight);
      api.getWikipediaNearby(camp.lat, camp.lng, 15000)
        .then(articles => {
          if (selectedCampRef.current?.id === camp.id) setWikiArticles(articles);
        })
        .catch(() => {
          if (selectedCampRef.current?.id === camp.id) setWikiArticles([]);
        })
        .finally(() => {
          if (selectedCampRef.current?.id === camp.id) setLoadingWiki(false);
        });
      return true;
    } catch (e: any) {
      setLoadingWiki(false);
      if (e instanceof PaywallError) {
        setPaywallCode(e.code); setPaywallMessage(e.message); setPaywallVisible(true);
        return false;
      }
      return true;
    } finally {
      if (selectedCampRef.current?.id === camp.id) setLoadingInsight(false);
    }
  }

  async function fetchRouteBrief(forceRefresh = false) {
    if (!activeTrip) return;
    if (!forceRefresh) {
      const saved = routeBrief ?? await loadSavedTripAi<RouteBrief>(activeTrip, 'route_brief');
      if (saved) {
        setRouteBrief(saved);
        setRouteBriefSaved(true);
        setShowRouteBrief(true);
        return;
      }
    }
    setLoadingBrief(true);
    try {
      const briefReports = routeAlerts.filter(alert => {
        const provider = String((alert as any).provider || '').toLowerCase();
        const type = String(alert.type || '').toLowerCase();
        const subtype = String(alert.subtype || '').toLowerCase();
        const severity = String(alert.severity || '').toLowerCase();
        if (provider === 'tomtom' && type === 'traffic' && subtype === 'summary') return false;
        if (provider === 'tomtom' && type === 'traffic' && !['critical', 'high'].includes(severity)) return false;
        return true;
      });
      const brief = await api.getRouteBrief({
        trip_name: activeTrip.plan.trip_name,
        waypoints: usableTripWaypoints(activeTrip.plan.waypoints),
        reports: briefReports,
      });
      const normalized = normalizeRouteBrief(brief, activeTrip, routeAlerts);
      trackPhase0Event('phase0_route_brief_generated', {
        trip_id: activeTrip.trip_id,
        source: 'ai',
        alert_count: briefReports.length,
        readiness_score: normalized.readiness_score,
      });
      setRouteBrief(normalized);
      setRouteBriefSaved(true);
      saveTripAi(activeTrip, 'route_brief', normalized).catch(() => {});
      setShowRouteBrief(true);
    } catch (e: any) {
      if (e instanceof PaywallError) {
        setPaywallCode(e.code); setPaywallMessage(e.message); setPaywallVisible(true);
      } else {
        const fallback = localRouteBrief(activeTrip, routeAlerts);
        trackPhase0Event('phase0_route_brief_generated', {
          trip_id: activeTrip.trip_id,
          source: 'fallback',
          alert_count: routeAlerts.length,
          readiness_score: fallback.readiness_score,
        });
        setRouteBrief(fallback);
        setRouteBriefSaved(true);
        saveTripAi(activeTrip, 'route_brief', fallback).catch(() => {});
        setShowRouteBrief(true);
      }
    } finally {
      setLoadingBrief(false);
    }
  }

  async function fetchPackingList(forceRefresh = false) {
    if (!activeTrip) return;
    if (!forceRefresh) {
      const saved = packingList ?? await loadSavedTripAi<PackingList>(activeTrip, 'packing_list');
      if (saved) {
        setPackingList(saved);
        setPackingListSaved(true);
        setShowPacking(true);
        return;
      }
    }
    setLoadingPacking(true);
    try {
      const list = await api.getPackingList({
        trip_name: activeTrip.plan.trip_name,
        duration_days: activeTrip.plan.duration_days,
        road_types: [...new Set(activeTrip.plan.daily_itinerary.map(d => d.road_type))],
        land_types: [...new Set(usableTripWaypoints(activeTrip.plan.waypoints).map(w => w.land_type))],
        states: activeTrip.plan.states,
      });
      setPackingList(list);
      setPackingListSaved(true);
      saveTripAi(activeTrip, 'packing_list', list).catch(() => {});
      setShowPacking(true);
    } catch {}
    setLoadingPacking(false);
  }

  function tripDayAnchors(day: number) {
    const allStops = usableTripWaypoints(activeTrip?.plan.waypoints)
      .filter(w => w.lat != null && w.lng != null && isFinite(w.lat) && isFinite(w.lng));
    const dayStops = allStops
      .filter(w => w.day === day && w.lat != null && w.lng != null && isFinite(w.lat) && isFinite(w.lng));
    const ordered = [
      ...dayStops.filter(w => w.type === 'camp'),
      ...dayStops.filter(w => w.type !== 'camp' && w.type !== 'fuel'),
      ...dayStops.filter(w => w.type === 'fuel'),
      ...allStops,
    ];
    const seen = new Set<string>();
    return ordered.filter(w => {
      const key = `${w.lat!.toFixed(3)}:${w.lng!.toFixed(3)}`;
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    }).slice(0, 5);
  }

  function tripDayCampContext(day: number) {
    const allStops = usableTripWaypoints(activeTrip?.plan.waypoints)
      .filter(w => w.lat != null && w.lng != null && isFinite(w.lat) && isFinite(w.lng));
    const dayStops = allStops.filter(w => w.day === day);
    const previousStops = allStops.filter(w => w.day < day);
    const endpoint = [...dayStops].reverse().find(w => w.type === 'camp' || w.type === 'motel')
      ?? [...dayStops].reverse().find(w => w.type !== 'fuel')
      ?? dayStops[dayStops.length - 1]
      ?? null;
    const previous = [...previousStops].reverse().find(w => w.type === 'camp' || w.type === 'motel')
      ?? previousStops[previousStops.length - 1]
      ?? null;
    return { endpoint, previous };
  }

  async function openCampPicker(day?: number) {
    if (!activeTrip) return;
    const nextDay = day ?? selectedDay ?? activeTrip.plan.daily_itinerary[0]?.day ?? 1;
    let { endpoint, previous } = tripDayCampContext(nextDay);
    setCampPickerDay(nextDay);
    setCampPickerVisible(true);
    setCampPickerError('');
    setCampCandidates([]);
    if (!endpoint) {
      const fallback = tripDayNearbyCenters(nextDay)[0] ?? previous;
      if (fallback?.lat && fallback?.lng) {
        endpoint = {
          day: nextDay,
          name: `Day ${nextDay} area`,
          lat: fallback.lat,
          lng: fallback.lng,
          type: 'waypoint',
        } as Waypoint;
      }
    }
    if (!endpoint) {
      setCampPickerError('Pick a spot on the map or add a stop for this day, then search overnight options.');
      return;
    }
    setCampPickerLoading(true);
    try {
      const localTripCamps = (activeTrip.campsites ?? [])
        .filter(c => c.lat != null && c.lng != null && isFinite(c.lat) && isFinite(c.lng))
        .filter(c => {
          const endpointMi = haversineKm(endpoint.lat!, endpoint.lng!, c.lat, c.lng) * 0.621371;
          return c.recommended_day === nextDay || endpointMi <= 35;
        }) as CampsitePin[];
      const batches = await Promise.allSettled([
        api.getNearbyCamps(endpoint.lat!, endpoint.lng!, 35, []),
        api.searchCampsites(endpoint.lat!, endpoint.lng!, 40, []),
      ]);
      const seen = new Set<string>();
      const candidates: CampsitePin[] = [];
      for (const camp of localTripCamps) {
        const key = String(camp.id || `${camp.name}:${camp.lat.toFixed(4)}:${camp.lng.toFixed(4)}`);
        if (seen.has(key)) continue;
        seen.add(key);
        candidates.push(camp);
      }
      for (const batch of batches) {
        if (batch.status !== 'fulfilled') continue;
        for (const camp of batch.value) {
          const key = String(camp.id || `${camp.name}:${camp.lat.toFixed(4)}:${camp.lng.toFixed(4)}`);
          if (seen.has(key)) continue;
          seen.add(key);
          candidates.push(camp);
        }
      }
      const sorted = candidates
        .map(c => {
          const endpointMi = haversineKm(endpoint.lat!, endpoint.lng!, c.lat, c.lng) * 0.621371;
          const legMi = previous
            ? pointSegmentDistanceMi(
                { lat: c.lat, lng: c.lng },
                { lat: previous.lat!, lng: previous.lng! },
                { lat: endpoint.lat!, lng: endpoint.lng! }
              )
            : endpointMi;
          const tags = new Set((c.tags ?? []).map(t => t.toLowerCase()));
          const publicLandBonus = tags.has('dispersed') || tags.has('blm') || tags.has('usfs') ? -8 : 0;
          const developedPenalty = c.reservable ? 2 : 0;
          return {
            ...c,
            recommended_day: nextDay,
            route_distance_mi: endpointMi,
            route_fit: c.route_fit ?? (endpointMi <= 5 ? 'on_route' : endpointMi <= 18 ? 'short_detour' : 'detour'),
            _score: endpointMi + Math.min(legMi, 30) * 0.12 + publicLandBonus + developedPenalty,
          };
        })
        .filter(c => (c.route_distance_mi ?? 999) <= 45)
        .sort((a, b) => ((a as any)._score ?? 999) - ((b as any)._score ?? 999))
        .map(({ _score, ...c }: CampsitePin & { _score?: number }) => c)
        .slice(0, 30);
      setCampCandidates(sorted);
      if (sorted.length === 0) setCampPickerError('No camps found near this day yet. Try the map search or choose a nearby map camp and tap Use for Day.');
    } catch (e: any) {
      if (e instanceof PaywallError) {
        setPaywallCode(e.code); setPaywallMessage(e.message); setPaywallVisible(true);
        setCampPickerVisible(false);
      } else {
        setCampPickerError('Could not load camps for this day.');
      }
    } finally {
      setCampPickerLoading(false);
    }
  }

  function useCampForTripDay(camp: CampsitePin, dayOverride?: number) {
    const day = dayOverride ?? campPickerDay;
    if (!activeTrip || !day) return;
    const campWaypoint: Waypoint = {
      day,
      name: camp.name,
      type: 'camp',
      description: camp.description || 'Selected camp for this trip day.',
      land_type: camp.land_type || 'camp',
      notes: [
        camp.cost ? `Cost: ${camp.cost}` : null,
        camp.reservable ? 'Reservable' : 'First-come or dispersed',
        camp.route_distance_mi != null ? `${camp.route_distance_mi.toFixed(1)} mi from this day` : null,
      ].filter(Boolean).join(' · '),
      lat: camp.lat,
      lng: camp.lng,
      verified_source: camp.verified_source ?? 'camp_picker',
      verified_match: true,
    };

    const original = activeTrip.plan.waypoints ?? [];
    const existingCampIndex = original.reduce(
      (last, w, idx) => w.day === day && (w.type === 'camp' || w.type === 'motel' || isPlanningTargetWaypoint(w)) ? idx : last,
      -1
    );
    const replacedWaypoint = existingCampIndex >= 0 ? original[existingCampIndex] : null;
    let nextWaypoints: Waypoint[];
    if (existingCampIndex >= 0) {
      nextWaypoints = original.map((w, idx) => idx === existingCampIndex ? campWaypoint : w);
    } else {
      const lastDayIndex = original.reduce((last, w, idx) => w.day === day ? idx : last, -1);
      nextWaypoints = [...original];
      nextWaypoints.splice(lastDayIndex >= 0 ? lastDayIndex + 1 : nextWaypoints.length, 0, campWaypoint);
    }
    const recalculatedWps = nextWaypoints
      .filter(w => w.lat != null && w.lng != null && isFinite(w.lat) && isFinite(w.lng))
      .map(w => ({ ...w, lat: w.lat!, lng: w.lng! })) as WP[];
    const nextDaily = activeTrip.plan.daily_itinerary.map(d => (
      d.day === day || d.day === day + 1
        ? { ...d, est_miles: dayMileageFromWaypoints(recalculatedWps, d.day) }
        : d
    ));

    const nextTrip = {
      ...activeTrip,
      campsites: [
        { ...camp, recommended_day: day },
        ...(activeTrip.campsites ?? []).filter(c => {
          if (c.id === camp.id || c.recommended_day === day) return false;
          if (!replacedWaypoint) return true;
          if (c.name === replacedWaypoint.name) return false;
          return !(Math.abs(c.lat - (replacedWaypoint.lat ?? 0)) < 0.001 && Math.abs(c.lng - (replacedWaypoint.lng ?? 0)) < 0.001);
        }),
      ],
      plan: {
        ...activeTrip.plan,
        waypoints: nextWaypoints,
        daily_itinerary: nextDaily,
      },
    };
    setActiveTrip(nextTrip);
    setIsRouted(false);
    setRouteSteps([]);
    setRouteLegs([]);
    setLastRouteCoords([]);
    setRouteProgress(null);
    storage.del('trailhead_active_route').catch(() => {});
    deleteRouteGeometry(activeTrip.trip_id).catch(() => {});
    saveOfflineTrip(nextTrip).catch(() => {});
    setCampPickerVisible(false);
    setQuickToast(`Day ${day} camp updated`);
    setTimeout(() => setQuickToast(''), 2500);
    nativeMapRef.current?.flyTo(camp.lat, camp.lng, 12);
  }

  async function saveActiveRouteSnapshot() {
    if (activeTrip) await saveOfflineTrip(activeTrip);
    if (activeTrip?.trip_id) {
      await storage.get('trailhead_active_route').then(raw => {
        if (!raw) return;
        const cached = JSON.parse(raw);
        if (cached.tripId === activeTrip.trip_id) return saveRouteGeometry(activeTrip.trip_id, cached);
      }).catch(() => {});
    }
  }

