  async function loadCampsInArea(bounds: { n: number; s: number; e: number; w: number; zoom: number }, types: string[]): Promise<CampsitePin[] | null> {
    if (!showCampPins) {
      setAreaCamps([]);
      return null;
    }
    if ((bounds.zoom ?? 0) < MIN_CAMP_SEARCH_ZOOM) {
      setSearchResult({ count: -2 });
      setTimeout(() => setSearchResult(null), 3000);
      return null;
    }
    // Center of the visible map area (not GPS location)
    const centerLat = (bounds.n + bounds.s) / 2;
    const centerLng = (bounds.e + bounds.w) / 2;
    // Half-diagonal of visible area in miles, capped so freecam searches can reach a wider route window.
    const latMi = ((bounds.n - bounds.s) / 2) * 69;
    const lngMi = ((bounds.e - bounds.w) / 2) * 69 * Math.cos(centerLat * Math.PI / 180);
    const radiusMi = Math.min(Math.ceil(Math.sqrt(latMi * latMi + lngMi * lngMi)), MAX_FREECAM_CAMP_SEARCH_RADIUS_MI);
    setIsLoadingAreaCamps(true);
    setMapMoved(false);
    setSearchResult(null);
    try {
      const [campsResult, fullResult, smartPackResult] = await Promise.allSettled([
        api.getNearbyCamps(centerLat, centerLng, radiusMi, types),
        api.getNearbyFullness(centerLat, centerLng, radiusMi * 0.6),
        api.getNearbySmartPack(centerLat, centerLng, Math.min(Math.max(radiusMi, 12), 45), placeCategoryRequest()),
      ]);
      const camps = campsResult.status === 'fulfilled' ? campsResult.value : [];
      if (campsResult.status === 'rejected' && campsResult.reason instanceof PaywallError) {
        setPaywallCode(campsResult.reason.code);
        setPaywallMessage(campsResult.reason.message);
        setPaywallVisible(true);
        setIsLoadingAreaCamps(false);
        return null;
      }
      const fullIds = new Set(
        fullResult.status === 'fulfilled' ? fullResult.value.map(f => f.camp_id) : []
      );
      const smartPlaces = smartPackResult.status === 'fulfilled' ? (smartPackResult.value.places ?? []) : [];
      const liveCampPins = smartPlaces
        .map(p => smartPlaceToCampPin(p as OsmPoi))
        .filter((p): p is CampsitePin => !!p);
      const offlineCampPins = offlinePlacePois
        .filter(p => CAMP_PLACE_TYPES.has(String(p.type || '')))
        .filter(p => campMatchesFilters(p, types))
        .filter(p => p.lat >= bounds.s && p.lat <= bounds.n && p.lng >= bounds.w && p.lng <= bounds.e)
        .map(p => ({
          ...p,
          route_distance_mi: haversineKm(centerLat, centerLng, p.lat, p.lng) * 0.621371,
        }))
        .filter(p => (p.route_distance_mi ?? 999) <= Math.max(radiusMi, 8))
        .sort((a, b) => (a.route_distance_mi ?? 999) - (b.route_distance_mi ?? 999))
        .map(offlinePlaceToCampPin)
        .filter((p): p is CampsitePin => !!p);
    const seenCampKeys = new Set<string>();
    const mergedCamps: CampsitePin[] = [];
      for (const camp of [...camps, ...liveCampPins, ...offlineCampPins].filter(camp => campMatchesFilters(camp, types))) {
        const key = campKey(camp);
        const fuzzy = `${String(camp.name || '').toLowerCase().trim()}:${camp.lat.toFixed(4)}:${camp.lng.toFixed(4)}`;
        if (seenCampKeys.has(key) || seenCampKeys.has(fuzzy)) continue;
        seenCampKeys.add(key);
        seenCampKeys.add(fuzzy);
        mergedCamps.push(camp);
        if (mergedCamps.length >= 180) break;
      }
      const tagged = rankCopilotCampsForSearch(
        mergedCamps.map(c => ({ ...c, full: fullIds.has(c.id) ? 1 : 0 })),
        { lat: centerLat, lng: centerLng },
      );
      const smartNonCampPois = smartPlaces
        .filter(p => String(p.type) !== 'camp')
        .filter(p => (p.name && p.name.trim()) || UTILITY_PLACE_TYPES.has(String(p.type || ''))) as OsmPoi[];
      if (smartNonCampPois.length > 0) mergePoiBatch(smartNonCampPois, { lat: centerLat, lng: centerLng });
      // Feed results to WebView (legacy path) AND native map
      webRef.current?.postMessage(JSON.stringify({ type: 'set_camps', pins: tagged }));
      setAreaCamps(tagged);
      setSearchResult({ count: tagged.length });
      setTimeout(() => setSearchResult(null), 3000);
      setIsLoadingAreaCamps(false);
      return tagged;
    } catch (e: any) {
      if (e instanceof PaywallError) {
        setPaywallCode(e.code); setPaywallMessage(e.message); setPaywallVisible(true);
      } else {
        setSearchResult({ count: -1 });
        setTimeout(() => setSearchResult(null), 3000);
      }
    }
    setIsLoadingAreaCamps(false);
    return null;
  }

  function restoreCachedActiveRoute(target: 'web' | 'native') {
    if (!activeTrip?.trip_id) return;
    const serverRoute = activeTrip.route_geometry;
    if (serverRoute && Array.isArray(serverRoute.coords) && serverRoute.coords.length >= 2) {
      const steps = serverRoute.steps ?? [];
      const legs = serverRoute.legs ?? [];
      const totalDistance = serverRoute.totalDistance ?? serverRoute.total_distance ?? 0;
      const totalDuration = serverRoute.totalDuration ?? serverRoute.total_duration ?? 0;
      if (target === 'native') {
        nativeMapRef.current?.restoreRoute(serverRoute.coords, steps, legs, totalDistance, totalDuration);
        setLastRouteCoords(serverRoute.coords);
      } else {
        webRef.current?.postMessage(JSON.stringify({
          type: 'restore_route',
          coords: serverRoute.coords,
          steps,
          legs,
          total_distance: totalDistance,
          total_duration: totalDuration,
        }));
      }
      saveRouteGeometry(activeTrip.trip_id, {
        ...serverRoute,
        steps,
        legs,
        totalDistance,
        totalDuration,
      }).catch(() => {});
      return;
    }
    loadRouteGeometry(activeTrip.trip_id).then(saved => {
      if (!saved || !Array.isArray(saved.coords) || saved.coords.length < 2) return;
      const steps = saved.steps ?? [];
      const legs = saved.legs ?? [];
      const totalDistance = saved.totalDistance ?? saved.total_distance ?? 0;
      const totalDuration = saved.totalDuration ?? saved.total_duration ?? 0;

      if (target === 'native') {
        nativeMapRef.current?.restoreRoute(saved.coords, steps, legs, totalDistance, totalDuration);
        setLastRouteCoords(saved.coords);
        return;
      }

      webRef.current?.postMessage(JSON.stringify({
        type: 'restore_route',
        coords: saved.coords,
        steps,
        legs,
        total_distance: totalDistance,
        total_duration: totalDuration,
      }));
    }).catch(() => {});

    storage.get('trailhead_active_route').then(raw => {
      if (!raw) return;
      try {
        const cached = JSON.parse(raw);
        if (cached.tripId !== activeTrip.trip_id) return;
        if (!Array.isArray(cached.coords) || cached.coords.length < 2) return;

        const steps = cached.steps ?? [];
        const legs = cached.legs ?? [];
        const totalDistance = cached.totalDistance ?? cached.total_distance ?? 0;
        const totalDuration = cached.totalDuration ?? cached.total_duration ?? 0;

        if (target === 'native') {
          nativeMapRef.current?.restoreRoute(cached.coords, steps, legs, totalDistance, totalDuration);
          setLastRouteCoords(cached.coords);
          return;
        }

        webRef.current?.postMessage(JSON.stringify({
          type: 'restore_route',
          coords: cached.coords,
          steps,
          legs,
          total_distance: totalDistance,
          total_duration: totalDuration,
        }));
      } catch {}
    }).catch(() => {});
  }

  const runLandCheck = useCallback((lat: number, lng: number) => {
    setLandCheck(null);
    setLandCheckLoading(true);
    if (landCheckDismissTimer.current) clearTimeout(landCheckDismissTimer.current);
    api.getLandCheck(lat, lng)
      .then(result => {
        setLandCheck(result);
        setLandCheckLoading(false);
        landCheckDismissTimer.current = setTimeout(() => {
          setLandCheck(null);
          setLandCheckLoading(false);
        }, 8000);
      })
      .catch(() => {
        setLandCheckLoading(false);
      });
  }, []);

  // ── WebView message handler ──────────────────────────────────────────────────

  function onWebMessage(e: any) {
    try {
      const msg = JSON.parse(e.nativeEvent.data);
      if (msg.type === 'map_ready') {
        if (viewportRef.current) loadCampsInArea(viewportRef.current, activeFilters);
        // If we restored a trip from cache (offline relaunch), replay its route geometry
        // into the WebView so navigation works without re-fetching from Mapbox Directions.
        restoreCachedActiveRoute('web');
      }
      if (msg.type === 'map_bounds') {
        const bounds = { n: msg.n, s: msg.s, e: msg.e, w: msg.w, zoom: msg.zoom };
        viewportRef.current = bounds;
        setMapZoom(msg.zoom ?? 10);
        if ((msg.zoom ?? 0) >= 9) setMapMoved(true);
        const pinLat = (msg.n + msg.s) / 2;
        const pinLng = (msg.e + msg.w) / 2;
        const pinRadius = Math.max(1.0, Math.min(4.0, Math.max(Math.abs(msg.n - msg.s), Math.abs(msg.e - msg.w)) / 2 + 0.5));
        refreshCommunityPins({ lat: pinLat, lng: pinLng }, pinRadius, false);
        queueViewportPlaceFetch(bounds);
        queueViewportCampFetch(bounds);
        queueWaterNavigationLineFetch(bounds);
        queueRenderedFeatureRefresh(bounds);
        handleWeatherBounds(bounds);
      }
      if (msg.type === 'search_area') {
        // Legacy WebView button — handled by native button now, but keep as fallback
        const bounds = { n: msg.n, s: msg.s, e: msg.e, w: msg.w, zoom: msg.zoom };
        viewportRef.current = bounds;
        loadCampsInArea(bounds, activeFilters);
      }
      if (msg.type === 'map_tapped') {
        setSelectedCamp(null);
        setTappedTrail(null);
      }
      if (msg.type === 'route_persist' && Array.isArray(msg.coords)) {
        // Cache the freshly-routed geometry + steps so we can replay offline
        const payload = {
          coords: msg.coords, steps: msg.steps ?? [], legs: msg.legs ?? [],
          total_distance: msg.total_distance, total_duration: msg.total_duration,
          route_source: msg.route_source ?? msg.routeSource ?? null,
          tripId: activeTrip?.trip_id ?? null,
          ts: Date.now(),
        };
        if (payload.route_source) setRouteSourceDebug(String(payload.route_source));
        storage.set('trailhead_active_route', JSON.stringify(payload)).catch(() => {});
        saveRouteGeometry(activeTrip?.trip_id, payload).catch(() => {});
      }
      if (msg.type === 'route_ready') {
        setIsRouted(msg.routed);
        setRouteFromCache(!!msg.fromCache);
        const source = String(msg.routeSource ?? msg.route_source ?? msg.routeSourceLabel ?? msg.route_source_label ?? '').trim();
        setRouteSourceDebug(source);
        if (source) setRouteDebug(source);
        setRouteSteps(msg.steps ?? []);
        setRouteLegs(msg.legs ?? []);
        setRouteProgress(null);
        if (msg.fromIdx !== undefined) setRouteLegOffset(msg.fromIdx);
        setIsRerouting(false);
        isReroutingRef.current = false;
        reconnectRouteRefreshRef.current = false;
        if (rerouteTimeoutRef.current) { clearTimeout(rerouteTimeoutRef.current); rerouteTimeoutRef.current = null; }
      }
      if (msg.type === 'route_progress') {
        if (isReroutingRef.current) return;
        const distanceM = Number(msg.distanceM);
        const remainingM = Number(msg.remainingM);
        const routeDistanceM = Number(msg.routeDistanceM);
        const deviationM = Number(msg.deviationM);
        const segmentIdx = Number(msg.segmentIdx);
        if ([distanceM, remainingM, routeDistanceM, deviationM, segmentIdx].every(Number.isFinite)) {
          setRouteProgress({ distanceM, remainingM, routeDistanceM, deviationM, segmentIdx });
        }
      }
      if (msg.type === 'off_route' && navRef.current.active) {
        const now = Date.now();
        if (isReroutingRef.current || now - lastRerouteRef.current < 10000) return;
        // Suppress only right at a maneuver; larger distances can hide true wrong turns on backroads.
        const curStep = routeStepsRef.current[stepIdxRef.current];
        if (curStep?.lat != null && msg.lat != null) {
          const stepDist = haversineKm(msg.lat as number, msg.lng as number, curStep.lat, curStep.lng!) * 1000;
          if (stepDist < 100) return;
        }
        // Advance past any waypoints we may have already driven through
        const { wps } = navRef.current;
        let bestIdx = navRef.current.idx;
        while (bestIdx < wps.length - 1) {
          const d = haversineKm(msg.lat, msg.lng, wps[bestIdx].lat, wps[bestIdx].lng);
          if (d < 0.4) { bestIdx++; } else break;
        }
        lastRerouteRef.current = now;
        setIsRerouting(true);
        isReroutingRef.current = true;
        setRouteProgress(null);
        if (USE_IOS_NATIVE_NAV_ENGINE) stopNavigationSession().catch(() => {});
        if (rerouteTimeoutRef.current) clearTimeout(rerouteTimeoutRef.current);
        rerouteTimeoutRef.current = setTimeout(() => { setIsRerouting(false); isReroutingRef.current = false; }, 15000);
        if (bestIdx !== navRef.current.idx) {
          setNavIdx(bestIdx);
          navRef.current.idx = bestIdx;
        }
        webRef.current?.postMessage(JSON.stringify({
          type: 'reroute_from',
          lat: msg.lat, lng: msg.lng,
          fromIdx: bestIdx,
        }));
        nativeMapRef.current?.rerouteFrom(msg.lat, msg.lng, bestIdx);
        setRouteLegOffset(bestIdx);
        setOffRouteWarn(false);
        if (offRouteWarnTimer.current) clearTimeout(offRouteWarnTimer.current);
        safeSpeech('Off route. Recalculating.', { rate: 0.88, pitch: 1.05 });
      }
      if (msg.type === 'off_route_warn' && navRef.current.active && !isReroutingRef.current) {
        // Suppress warn only right at the current maneuver; backroad intersections need faster feedback.
        const curStep = routeStepsRef.current[stepIdxRef.current];
        if (curStep?.lat != null && msg.lat != null) {
          const stepDist = haversineKm(msg.lat as number, msg.lng as number, curStep.lat, curStep.lng!) * 1000;
          if (stepDist < 100) return;
        }
        setOffRouteWarn(true);
        if (offRouteWarnTimer.current) clearTimeout(offRouteWarnTimer.current);
        offRouteWarnTimer.current = setTimeout(() => setOffRouteWarn(false), 18000);
      }
      if (msg.type === 'back_on_route') {
        setOffRouteWarn(false);
        if (offRouteWarnTimer.current) clearTimeout(offRouteWarnTimer.current);
      }
      if (msg.type === 'wp_tapped') {
        const wp = waypoints[msg.idx];
        if (wp) setTappedWp({ idx: msg.idx, wp });
      }
      if (msg.type === 'download_progress') {
        setDownloadProgress(msg.percent ?? 0);
        setDownloadTotal(msg.total ?? 0);
        setDownloadSaved(msg.saved ?? 0);
        if (msg.mb != null) setDownloadMB(String(msg.mb));
      }
      if (msg.type === 'download_complete') {
        setIsDownloading(false);
        setDownloadProgress(100);
        setDownloadLabel(prev => { if (prev) addCachedRegion(prev); return prev; });
        setTimeout(() => { setDownloadProgress(0); setDownloadSaved(0); setDownloadMB('0'); }, 3000);
      }
      if (msg.type === 'campsite_tapped') {
        const camp = (msg.camp as CampsitePin) || null;
        setSelectedCamp(camp);
        setCampDetail(null);
        setCampInsight(null);
        setWikiArticles([]);
        setCampFullness(null);
        setCampWeather(null);
        if (camp?.id) api.getCampFullness(camp.id).then(r => setCampFullness(r)).catch(() => {});
        if (camp?.lat && camp?.lng) api.getWeather(camp.lat, camp.lng, 3, weatherUnitMode).then(r => setCampWeather(r)).catch(() => {});
      }
      if (msg.type === 'poi_tapped') {
        const rawPoi = msg.poi as OsmPoi;
        if (rawPoi?.type === 'water' && rawPoi?.source === 'openseamap') {
          openPoiFeature(mapWaterNavigationPlace(rawPoi as any, Number(rawPoi.lat), Number(rawPoi.lng)));
        } else {
          openPoiFeature(rawPoi);
        }
      }
      if (msg.type === 'map_feature_selected') {
        const rawPoi = msg.poi as OsmPoi;
        if (rawPoi) openPoiFeature(rawPoi);
      }
      if (msg.type === 'waterbody_tapped' && Number.isFinite(Number(msg.lat)) && Number.isFinite(Number(msg.lng))) {
        openPoiFeature(mapWaterbodyPlace(Number(msg.lat), Number(msg.lng), msg.name, msg.kind));
      }
      if (msg.type === 'trail_tapped') {
        openTrailFromPoint(msg.name, msg.lat, msg.lng, msg.cls ?? 'path');
      }
      if (msg.type === 'base_camp_tapped') {
        setTappedTrail(null);
        const minId = `map_${msg.lat.toFixed(5)}_${msg.lng.toFixed(5)}`;
        const minPin: CampsitePin = {
          id: minId,
          name: msg.name,
          lat: msg.lat,
          lng: msg.lng,
          tags: [],
          land_type: 'Dispersed',
          description: '',
          reservable: false,
          cost: '',
          url: '',
          ada: false,
        };
        setSelectedCamp(minPin);
        setCampDetail(null);
        setCampInsight(null);
        setWikiArticles([]);
        setCampFullness(null);
        setCampWeather(null);
        api.getCampFullness(minId).then(r => setCampFullness(r)).catch(() => {});
        api.getWeather(msg.lat, msg.lng, 3, weatherUnitMode).then(r => setCampWeather(r)).catch(() => {});
        // Silently upgrade to full camp data if our backend has it
        api.getNearbyCamps(msg.lat, msg.lng, 2).then(results => {
          if (!results.length) return;
          const match = strictBackendCampMatch(minPin, results);
          if (!match) return;
          // Only update if user hasn't closed/changed the card
          setSelectedCamp(prev => prev?.id === minId ? match : prev);
        }).catch(() => {});
      }
      if (msg.type === 'map_long_press') {
        runLandCheck(msg.lat, msg.lng);
      }
    } catch {}
  }

  async function handleReportFull() {
    if (!selectedCamp || fullnessVoting) return;
    setFullnessVoting(true);
    try {
      const res = await api.reportCampFull(selectedCamp.id, {
        camp_name: selectedCamp.name, lat: selectedCamp.lat, lng: selectedCamp.lng,
      });
      const updated = await api.getCampFullness(selectedCamp.id).catch(() => null);
      setCampFullness(updated);
      if (res.credits_earned > 0) {
        setQuickToast(`+${res.credits_earned} credits`);
        setTimeout(() => setQuickToast(''), 2500);
      }
    } catch (e: any) {
      Alert.alert('Error', e.message ?? 'Could not submit report');
    }
    setFullnessVoting(false);
  }

  async function handleFullnessVote(action: 'confirm' | 'dispute') {
    if (!selectedCamp || fullnessVoting) return;
    setFullnessVoting(true);
    try {
      if (action === 'confirm') await api.confirmCampFull(selectedCamp.id);
      else await api.disputeCampFull(selectedCamp.id);
      const updated = await api.getCampFullness(selectedCamp.id).catch(() => null);
      setCampFullness(updated);
    } catch (e: any) {
      Alert.alert('Error', e.message ?? 'Could not submit vote');
    }
    setFullnessVoting(false);
  }

  async function loadCampDetailForCamp(camp: CampsitePin, opts: { showModal?: boolean; loadInsight?: boolean } = {}) {
    setLoadingDetail(true);
    setCampInsight(null);
    setWikiArticles([]);
    setFieldReports([]);
    setFieldReportSummary(null);
    setCampComments([]);
    setCampCanonicalId(null);
    setShowCampCommentForm(false);
    setCampCommentText('');
    setShowFieldReportForm(false);
    resetFieldReportForm();
    const minimal = minimalCampDetail(camp);
    setCampDetail(minimal);
    if (opts.showModal) setShowCampDetail(true);
    setLoadingDetail(false);
    let detail: CampsiteDetail;
    try {
      detail = await api.getCampsiteDetail(camp.id);
    } catch {
      detail = minimal;
    }
    detail = normalizeCampDetailArrays(detail);
    detail = await enrichCampDetailWithGoogle(detail, camp);
    if (selectedCampRef.current?.id !== camp.id) {
      return;
    }
    setCampDetail(detail);
    if (opts.loadInsight) openCampInsight(camp, detail).catch(() => {});
    if (selectedCampRef.current?.id !== camp.id) {
      return;
    }
    recordReviewMoment('camp_viewed')
      .then(async shouldShow => {
        if (!shouldShow) return;
        await markReviewPromptShown();
        setReviewPromptVisible(true);
      })
      .catch(() => {});
    // Load field reports in background
    api.getFieldReports(camp.id).then(r => {
      if (selectedCampRef.current?.id === camp.id) setFieldReports(r);
    }).catch(() => {});
    api.getFieldReportSummary(camp.id).then(r => {
      if (selectedCampRef.current?.id === camp.id) setFieldReportSummary(r);
    }).catch(() => {});
    api.canonicalizePlace({
      id: camp.id,
      name: camp.name,
      lat: camp.lat,
      lng: camp.lng,
      source: camp.source || 'camp',
      source_label: camp.source_badge || camp.verified_source || camp.source || camp.land_type || 'Camp source',
      provider_place_id: camp.provider_place_id,
      place_id: camp.place_id,
      type: 'camp',
      category: 'camp',
      subtype: camp.land_type,
      official_url: camp.official_url || camp.url,
      booking_url: camp.booking_url,
      url: camp.official_url || camp.url,
      photo_url: camp.photo_url,
      summary: camp.description,
      address: camp.address,
      phone: camp.phone,
      rating: camp.rating,
      rating_count: camp.rating_count,
      reservable: camp.reservable,
      amenities: camp.amenities,
    }).then(({ place }) => {
      if (selectedCampRef.current?.id !== camp.id) return;
      setCampCanonicalId(place.trailhead_place_id);
      setCampComments((place.comments ?? []) as CampComment[]);
    }).catch(() => {
      api.getCampComments(camp.id).then(r => {
        if (selectedCampRef.current?.id === camp.id) setCampComments(r);
      }).catch(() => {});
    });
  }

  async function openCampSiteCard(site: NonNullable<CampsiteDetail['campsites']>[number], parentDetail: CampsiteDetail, parentCamp: CampsitePin) {
    const facilityId = String(site.facility_id || parentDetail.id || parentCamp.id || '').replace(/^ridb_site:[^:]+:.+$/, '');
    const siteId = String(site.id || '').replace(/^ridb_site:[^:]+:/, '');
    const siteCardId = site.map_card_id || (facilityId && siteId ? `ridb_site:${facilityId}:${siteId}` : site.id || '');
    if (!siteCardId) return;
    setLoadingDetail(true);
    setQuickCampPhotoIndex(0);
    setCampInsight(null);
    setWikiArticles([]);
    setCampFullness(null);
    setCampWeather(null);
    try {
      const detail = normalizeCampDetailArrays(await api.getCampsiteDetail(String(siteCardId)));
      const photos = campPhotoItems(detail as unknown as CampsitePin, detail);
      const firstPhoto = photos[0]?.url || campPhotoUrl(detail.photo_url || detail.photos?.[0]);
      const sitePin = {
        ...parentCamp,
        ...detail,
        id: detail.id || String(siteCardId),
        name: detail.name || site.name || parentCamp.name,
        lat: Number(detail.lat ?? site.lat ?? parentDetail.lat ?? parentCamp.lat),
        lng: Number(detail.lng ?? site.lng ?? parentDetail.lng ?? parentCamp.lng),
        type: 'camp',
        land_type: detail.land_type || site.type || parentDetail.land_type || parentCamp.land_type,
        description: detail.description || `${site.name || 'Campsite'} at ${parentDetail.name || parentCamp.name}`,
        photos: detail.photos?.length ? detail.photos : (firstPhoto ? [firstPhoto] : []),
        photo_url: firstPhoto || detail.photo_url || parentCamp.photo_url,
        url: detail.url || detail.booking_url || detail.official_url || parentCamp.url,
        source: detail.source || 'ridb',
        verified_source: detail.verified_source || detail.source_badge || parentDetail.verified_source || 'Recreation.gov',
        source_badge: detail.source_badge || parentDetail.source_badge || 'Recreation.gov',
        parent_campground: (detail as any).parent_campground || {
          id: parentDetail.id,
          name: parentDetail.name,
          lat: parentDetail.lat,
          lng: parentDetail.lng,
          official_url: parentDetail.official_url || parentDetail.url,
          booking_url: parentDetail.booking_url,
        },
      } as CampsitePin;
      setSelectedCamp(sitePin);
      setCampDetail(detail);
      api.getCampFullness(sitePin.id).then(r => {
        if (selectedCampRef.current?.id === sitePin.id) setCampFullness(r);
      }).catch(() => {});
      if (Number.isFinite(sitePin.lat) && Number.isFinite(sitePin.lng)) {
        api.getWeather(sitePin.lat, sitePin.lng, 3, weatherUnitMode).then(r => {
          if (selectedCampRef.current?.id === sitePin.id) setCampWeather(r);
        }).catch(() => {});
      }
    } catch {
      setQuickToast('Could not load this Recreation.gov site');
      setTimeout(() => setQuickToast(''), 2800);
    } finally {
      setLoadingDetail(false);
    }
  }

  async function openCampDetail() {
    if (!selectedCamp) return;
    await loadCampDetailForCamp(selectedCamp, { showModal: true, loadInsight: true });
  }

  function closeCampDetail() {
    setShowCampDetail(false);
    setSelectedCamp(null);
    setCampDetail(null);
    setCampInsight(null);
    setCampGalleryIndex(null);
    setCampFullness(null);
    setCampWeather(null);
    setShowFieldReportForm(false);
    setShowCampCommentForm(false);
    setCampCommentText('');
    setCampComments([]);
    setCampCanonicalId(null);
    resetFieldReportForm();
  }

  async function enrichCampDetailWithGoogle(detail: CampsiteDetail, camp: CampsitePin): Promise<CampsiteDetail> {
    return detail;
  }

  function minimalCampDetail(camp: CampsitePin): CampsiteDetail {
    return {
      id: camp.id,
      name: camp.name,
      lat: camp.lat,
      lng: camp.lng,
      land_type: camp.land_type ?? '',
      description: camp.description ?? '',
      cost: camp.cost ?? '',
      reservable: camp.reservable ?? false,
      url: camp.url ?? '',
      ada: camp.ada ?? false,
      tags: Array.isArray(camp.tags) ? camp.tags : [],
      photos: Array.isArray(camp.photos) && camp.photos.length ? (camp.photos as any) : (camp.photo_url ? [camp.photo_url] : []),
      amenities: Array.isArray(camp.amenities) ? camp.amenities : [],
      site_types: Array.isArray(camp.site_types) ? camp.site_types : [],
      activities: [],
      campsites_count: 0,
      source: camp.source,
      verified_source: camp.source_badge || camp.verified_source,
      phone: camp.phone,
      address: camp.address,
      rating: camp.rating,
      rating_count: camp.rating_count,
      provider_place_id: camp.provider_place_id,
      place_id: camp.place_id,
      official_url: camp.official_url,
      booking_url: camp.booking_url,
      source_badge: camp.source_badge,
      source_freshness: camp.source_freshness,
      source_confidence_notes: camp.source_freshness,
      last_checked: camp.last_checked,
    } as CampsiteDetail;
  }

  function openCampEdit(mode: 'suggest' | 'admin') {
    const detail = campDetail ?? (selectedCamp ? minimalCampDetail(selectedCamp) : null);
    if (!detail) return;
    if (!campDetail) setCampDetail(detail);
    setCampEditMode(mode);
    setCampEditDraft({
      name: detail.name || '',
      description: stripHtml(detail.description || ''),
      cost: detail.cost || '',
      phone: detail.phone || '',
      url: detail.url || '',
      accessNotes: (detail as any).access_notes || '',
      bailOutNotes: (detail as any).bail_out_notes || '',
      stayLimit: (detail as any).stay_limit || '',
      reservationNotes: (detail as any).reservation_notes || '',
      sourceConfidenceNotes: (detail as any).source_confidence_notes || '',
      maxRigLength: (detail as any).max_rig_length || '',
      siteTypes: [...(detail.site_types ?? [])],
      amenities: [...(detail.amenities ?? [])],
      activities: [...(detail.activities ?? [])],
      note: '',
    });
    setShowCampEdit(true);
  }

  function toggleDraftList(key: 'siteTypes' | 'amenities' | 'activities', label: string) {
    setCampEditDraft(prev => {
      if (!prev) return prev;
      const list = prev[key];
      const next = list.includes(label) ? list.filter(x => x !== label) : [...list, label];
      return { ...prev, [key]: next };
    });
  }

  async function submitCampEdit() {
    if (!campDetail || !campEditDraft || campEditSaving) return;
    setCampEditSaving(true);
    try {
      const payload = {
        name: campEditDraft.name.trim(),
        description: campEditDraft.description.trim(),
        cost: campEditDraft.cost.trim(),
        phone: campEditDraft.phone.trim(),
        url: campEditDraft.url.trim(),
        access_notes: campEditDraft.accessNotes.trim(),
        bail_out_notes: campEditDraft.bailOutNotes.trim(),
        stay_limit: campEditDraft.stayLimit.trim(),
        reservation_notes: campEditDraft.reservationNotes.trim(),
        source_confidence_notes: campEditDraft.sourceConfidenceNotes.trim(),
        max_rig_length: campEditDraft.maxRigLength.trim(),
        site_types: campEditDraft.siteTypes,
        amenities: campEditDraft.amenities,
        activities: campEditDraft.activities,
      };
      if (campEditMode === 'admin' && user?.is_admin) {
        const res = await api.adminUpdateCampsite(campDetail.id, payload);
        setCampDetail(prev => prev ? { ...prev, ...res.override, admin_edited: true } as CampsiteDetail : prev);
        setQuickToast('Camp profile updated');
      } else {
        const res = await api.suggestCampsiteEdit(campDetail.id, {
          camp_name: campDetail.name,
          lat: campDetail.lat,
          lng: campDetail.lng,
          field: 'profile',
          value: JSON.stringify(payload),
          note: campEditDraft.note.trim() || undefined,
        });
        setQuickToast(`Edit sent · +${res.credits_earned} credits`);
      }
      setShowCampEdit(false);
      setTimeout(() => setQuickToast(''), 2500);
    } catch (e: any) {
      Alert.alert(campEditMode === 'admin' ? 'Admin edit failed' : 'Could not send edit', e.message ?? 'Try again in a moment.');
    } finally {
      setCampEditSaving(false);
    }
  }

  function resetFieldReportForm() {
    setFrSentiment(null); setFrAccess(null); setFrCrowd(null);
    setFrTags([]); setFrNote(''); setFrPhoto(null);
  }

  async function pickFieldReportPhoto() {
    const { status } = await ImagePicker.requestMediaLibraryPermissionsAsync();
    if (status !== 'granted') return;
    const result = await ImagePicker.launchImageLibraryAsync({
      mediaTypes: ImagePicker.MediaTypeOptions.Images,
      allowsEditing: true, quality: 0.5, base64: true,
    });
    if (!result.canceled && result.assets[0].base64) setFrPhoto(result.assets[0].base64);
  }

  async function submitFieldReport() {
    if (!selectedCamp || !frSentiment || !frAccess || !frCrowd) return;
    setFrSubmitting(true);
    try {
      const rigLabel = rigProfile?.make && rigProfile?.model
        ? `${rigProfile.year ? rigProfile.year + ' ' : ''}${rigProfile.make} ${rigProfile.model}`
        : undefined;
      const today = new Date().toISOString().split('T')[0];
      const res = await api.submitFieldReport(selectedCamp.id, {
        camp_name: selectedCamp.name, lat: selectedCamp.lat, lng: selectedCamp.lng,
        rig_label: rigLabel, visited_date: today,
        sentiment: frSentiment, access_condition: frAccess, crowd_level: frCrowd,
        tags: frTags, note: frNote || undefined, photo_data: frPhoto ?? undefined,
      });
      setQuickToast(`+${res.credits_earned} credits`);
      setTimeout(() => setQuickToast(''), 2500);
      setShowFieldReportForm(false);
      resetFieldReportForm();
      // Refresh lists
      api.getFieldReports(selectedCamp.id).then(setFieldReports).catch(() => {});
      api.getFieldReportSummary(selectedCamp.id).then(setFieldReportSummary).catch(() => {});
    } catch (e: any) {
      Alert.alert('Error', e.message ?? 'Could not submit field report');
    } finally {
      setFrSubmitting(false);
    }
  }

  function renderCampFieldReportForm() {
    return (
      <View style={s.frForm}>
        <Text style={s.frFormLabel}>How was it?</Text>
        <View style={s.frPillRow}>
          {([['loved_it','Loved it','#22c55e','heart'],['its_ok','It\'s OK','#f59e0b','thumbs-up'],['would_skip','Would skip','#ef4444','thumbs-down']] as const).map(([val, label, color, icon]) => (
            <TouchableOpacity key={val} style={[s.frSentimentBtn, frSentiment === val && { borderColor: color, backgroundColor: color + '22' }]}
              onPress={() => setFrSentiment(val)}>
              <Ionicons name={icon as keyof typeof Ionicons.glyphMap} size={12} color={frSentiment === val ? color : C.text2} />
              <Text style={[s.frSentimentBtnText, frSentiment === val && { color }]}>{label}</Text>
            </TouchableOpacity>
          ))}
        </View>

        <Text style={s.frFormLabel}>Access road</Text>
        <View style={s.frPillRow}>
          {([['easy','Easy'],['rough','Rough'],['four_wd_required','4WD Only']] as const).map(([val, label]) => (
            <TouchableOpacity key={val} style={[s.frPill, frAccess === val && s.frPillActive]}
              onPress={() => setFrAccess(val)}>
              <Text style={[s.frPillText, frAccess === val && s.frPillTextActive]}>{label}</Text>
            </TouchableOpacity>
          ))}
        </View>

        <Text style={s.frFormLabel}>Crowd level</Text>
        <View style={s.frPillRow}>
          {([['empty','Empty'],['few_rigs','A few rigs'],['packed','Packed']] as const).map(([val, label]) => (
            <TouchableOpacity key={val} style={[s.frPill, frCrowd === val && s.frPillActive]}
              onPress={() => setFrCrowd(val)}>
              <Text style={[s.frPillText, frCrowd === val && s.frPillTextActive]}>{label}</Text>
            </TouchableOpacity>
          ))}
        </View>

        <Text style={s.frFormLabel}>Tags (pick any)</Text>
        <View style={s.frTagPicker}>
          {['Great Views','Dog Friendly','Water Nearby','No Cell Signal','Fire Ring',
            'Very Quiet','High Clearance','Good Shade','Exposed/Windy','Creek Nearby',
            'Stargazing','Kids Friendly','Dusty Road','Fishing Nearby','Horse Friendly'].map(tag => {
            const on = frTags.includes(tag);
            return (
              <TouchableOpacity key={tag}
                style={[s.frTagPill, on && s.frTagPillOn]}
                onPress={() => setFrTags(p => on ? p.filter(t => t !== tag) : [...p, tag])}>
                <Text style={[s.frTagPillText, on && s.frTagPillTextOn]}>{tag}</Text>
              </TouchableOpacity>
            );
          })}
        </View>

        <Text style={s.frFormLabel}>Notes <Text style={s.frOptional}>(optional)</Text></Text>
        <TextInput
          style={s.frNoteInput}
          value={frNote}
          onChangeText={v => setFrNote(v.slice(0, 280))}
          placeholder="Road conditions, water source, anything useful..."
          placeholderTextColor={C.text3}
          multiline
          numberOfLines={3}
        />
        <Text style={s.frCharCount}>{frNote.length}/280</Text>

        <TouchableOpacity style={s.frPhotoBtn} onPress={pickFieldReportPhoto}>
          <Ionicons name={frPhoto ? 'checkmark-circle' : 'camera-outline'} size={16} color={frPhoto ? '#22c55e' : C.text3} />
          <Text style={[s.frPhotoBtnText, frPhoto && { color: '#22c55e' }]}>
            {frPhoto ? `Photo added (+${CREDIT_REWARDS.fieldReportPhotoBonus} credits)` : `Add photo (+${CREDIT_REWARDS.fieldReportPhotoBonus} credits)`}
          </Text>
        </TouchableOpacity>

        <View style={s.frFormActions}>
          <TouchableOpacity style={s.frCancelBtn} onPress={() => { setShowFieldReportForm(false); resetFieldReportForm(); }}>
            <Text style={s.frCancelText}>Cancel</Text>
          </TouchableOpacity>
          <TouchableOpacity
            style={[s.frSubmitBtn, (!frSentiment || !frAccess || !frCrowd || frSubmitting) && { opacity: 0.5 }]}
            onPress={submitFieldReport}
            disabled={!frSentiment || !frAccess || !frCrowd || frSubmitting}
          >
            {frSubmitting
              ? <ActivityIndicator size="small" color="#fff" />
              : <Text style={s.frSubmitText}>SUBMIT +{frPhoto ? 10 : 5} CREDITS</Text>}
          </TouchableOpacity>
        </View>
      </View>
    );
  }

  async function submitCampComment() {
    const detail = campDetail ?? selectedCamp;
    const text = campCommentText.trim();
    if (!detail || campCommentSubmitting || text.length < 2) return;
    setCampCommentSubmitting(true);
    try {
      if (campCanonicalId) {
        await api.submitPlaceComment(campCanonicalId, { body: text });
      } else {
        await api.submitCampComment(detail.id, {
          camp_name: detail.name,
          lat: detail.lat,
          lng: detail.lng,
          body: text,
        });
      }
      setCampCommentText('');
      setShowCampCommentForm(false);
      if (campCanonicalId) api.getPlaceComments(campCanonicalId).then(r => setCampComments(r as CampComment[])).catch(() => {});
      else api.getCampComments(detail.id).then(setCampComments).catch(() => {});
      setQuickToast('Comment posted');
      setTimeout(() => setQuickToast(''), 2200);
    } catch (e: any) {
      Alert.alert('Could not post comment', e.message ?? 'Try again in a moment.');
    } finally {
      setCampCommentSubmitting(false);
    }
  }

  async function submitTrailFieldReport() {
    if (!selectedTrail || !frSentiment || !frAccess || !frCrowd) return;
    setFrSubmitting(true);
    try {
      const rigLabel = rigProfile?.make && rigProfile?.model
        ? `${rigProfile.year ? rigProfile.year + ' ' : ''}${rigProfile.make} ${rigProfile.model}`
        : undefined;
      const today = new Date().toISOString().split('T')[0];
      const id = trailReportId(selectedTrail);
      const res = await api.submitTrailFieldReport(id, {
        trail_name: selectedTrail.name,
        lat: selectedTrail.lat,
        lng: selectedTrail.lng,
        rig_label: rigLabel,
        visited_date: today,
        sentiment: frSentiment,
        access_condition: frAccess,
        crowd_level: frCrowd,
        tags: frTags,
        note: frNote || undefined,
        photo_data: frPhoto ?? undefined,
      });
      setQuickToast(`+${res.credits_earned} credits`);
      setTimeout(() => setQuickToast(''), 2500);
      setShowTrailFieldReportForm(false);
      resetFieldReportForm();
      api.getTrailFieldReports(id).then(setTrailFieldReports).catch(() => {});
      api.getTrailFieldReportSummary(id).then(setTrailFieldReportSummary).catch(() => {});
    } catch (e: any) {
      Alert.alert('Error', e.message ?? 'Could not submit trail report');
    }
    setFrSubmitting(false);
  }

  // ── Stable map HTML (only rebuilds on trip/pins change) ─────────────────────

  const campsites = useMemo(() =>
    (activeTrip?.campsites ?? []).filter(c => c.lat && c.lng).map(c => ({ lat: c.lat, lng: c.lng, name: c.name })),
    [activeTrip?.trip_id]
  );
  const gas = useMemo(() =>
    (activeTrip?.gas_stations ?? []).filter(g => g.lat != null && g.lng != null && isFinite(g.lat) && isFinite(g.lng)).map(g => ({ lat: g.lat, lng: g.lng, name: g.name })),
    [activeTrip?.trip_id]
  );
  const trailSupportCamps = useMemo(() => [
    ...(activeTrip?.campsites ?? []).filter(c => c.lat != null && c.lng != null && isFinite(c.lat) && isFinite(c.lng)),
    ...areaCamps.filter(c => c.lat != null && c.lng != null && isFinite(c.lat) && isFinite(c.lng)),
  ], [activeTrip?.trip_id, areaCamps]);
  const allMapPois = useMemo(() => {
    if (!showPlacePins) return [];
    const allowedPlaces = new Set(activePlaceFilters);
    const seen = new Set<string>();
    const next: OsmPoi[] = [];
    const pushPoi = (p: OsmPoi | undefined | null, enforceFilter: boolean) => {
      if (!p || next.length >= MAX_ALL_MAP_POIS) return;
      if (enforceFilter && !placeMatchesFilters(p, allowedPlaces)) return;
      if (p.lat == null || p.lng == null || !isFinite(p.lat) || !isFinite(p.lng)) return;
      const key = p.id || `${p.name}:${p.lat.toFixed(4)}:${p.lng.toFixed(4)}`;
      if (seen.has(key)) return;
      seen.add(key);
      next.push(p);
    };
    for (const p of activeTrip?.route_pois ?? []) pushPoi(p, false);
    for (const p of pois) pushPoi(p, true);
    for (const p of liveRoutePois) pushPoi(p, true);
    let scannedOffline = 0;
    for (const p of offlinePlacePois) {
      scannedOffline += 1;
      pushPoi(p, true);
      if (next.length >= MAX_ALL_MAP_POIS || scannedOffline >= MAX_OFFLINE_POI_SCAN) break;
    }
    return next;
  }, [activeTrip?.trip_id, activePlaceFilters, liveRoutePois, offlinePlacePois, pois, showPlacePins]);
  const trailSourcePois = useMemo(() => {
    const seen = new Set<string>();
    const next: OsmPoi[] = [];
    const pushPoi = (p: OsmPoi | undefined | null) => {
      if (!p || next.length >= MAX_ALL_MAP_POIS) return;
      if (!['trail', 'trailhead', 'viewpoint', 'peak', 'hot_spring', 'water'].includes(p.type || '')) return;
      if (p.lat == null || p.lng == null || !isFinite(p.lat) || !isFinite(p.lng)) return;
      const key = p.id || `${p.name}:${p.lat.toFixed(4)}:${p.lng.toFixed(4)}`;
      if (seen.has(key)) return;
      seen.add(key);
      next.push(p);
    };
    for (const p of activeTrip?.route_pois ?? []) pushPoi(p);
    for (const p of pois) pushPoi(p);
    let scannedOffline = 0;
    for (const p of offlinePlacePois) {
      scannedOffline += 1;
      pushPoi(p);
      if (next.length >= MAX_ALL_MAP_POIS || scannedOffline >= MAX_OFFLINE_POI_SCAN) break;
    }
    return next;
  }, [activeTrip?.trip_id, activePlaceFilters, offlinePlacePois, pois]);
  const trailSupportFuel = useMemo(() => {
    const fromPois = allMapPois
      .filter(p => ['fuel', 'propane'].includes(p.type || '') && p.lat != null && p.lng != null && isFinite(p.lat) && isFinite(p.lng))
      .map(p => ({ lat: p.lat, lng: p.lng }));
    return [...gas, ...liveRouteGas, ...fromPois];
  }, [allMapPois, gas, liveRouteGas]);
  const routeSearchGas = useMemo(() => {
    const seen = new Set<string>();
    const next: Array<{ lat: number; lng: number; name: string }> = [];
    for (const station of [
      ...(activeTrip?.gas_stations ?? []).filter(g => g.lat != null && g.lng != null && isFinite(g.lat) && isFinite(g.lng)).map(g => ({ lat: g.lat, lng: g.lng, name: g.name || 'Fuel' })),
      ...liveRouteGas,
      ...allMapPois
        .filter(p => ['fuel', 'propane'].includes(p.type || '') && p.lat != null && p.lng != null && isFinite(p.lat) && isFinite(p.lng))
        .map(p => ({ lat: p.lat, lng: p.lng, name: p.name || 'Fuel' })),
    ]) {
      const key = `${station.name}:${station.lat.toFixed(4)}:${station.lng.toFixed(4)}`;
      if (seen.has(key)) continue;
      seen.add(key);
      next.push(station);
    }
    return next;
  }, [activeTrip?.trip_id, allMapPois, liveRouteGas]);
  const visibleCommunityPins = useMemo(() => {
    if (!showCommunityPins) return [];
    if (activePinFilters.length === 0) return [];
    const allowed = new Set(activePinFilters);
    return communityPins.filter(p => allowed.has(normalizedCommunityPinType(p)));
  }, [communityPins, activePinFilters, showCommunityPins]);
  const displayCommunityPins = useMemo(() =>
    visibleCommunityPins.map(p => ({ ...p, type: normalizedCommunityPinType(p) })),
    [visibleCommunityPins]
  );
  const routePois = useMemo(() => {
    const trailPinsActive = showTrailList || showDiscoveryPanel || discoveryMode === 'trails';
    const seen = new Set<string>();
    const next: OsmPoi[] = [];
    const pushPoi = (p: OsmPoi | undefined | null) => {
      if (!p || next.length >= MAX_VISIBLE_MAP_POIS) return;
      if (p.lat == null || p.lng == null || !isFinite(p.lat) || !isFinite(p.lng)) return;
      const type = p.type || 'poi';
      const key = p.id || `${type}:${p.name || 'poi'}:${p.lat.toFixed(5)}:${p.lng.toFixed(5)}`;
      if (seen.has(key)) return;
      seen.add(key);
      next.push({ ...p, id: p.id || key, type });
    };
    if (trailPinsActive) {
      for (const p of trailSourcePois) {
        if (TRAIL_DISCOVERY_PIN_TYPES.has(p.type || '')) pushPoi(p);
      }
    }
    for (const p of allMapPois) pushPoi(p);
    return next;
  }, [allMapPois, discoveryMode, showDiscoveryPanel, showTrailList, trailSourcePois]);
  const visibleMapFeatures = useMemo(() => {
    const vp = viewportRef.current;
    const center = vp
      ? { lat: (vp.n + vp.s) / 2, lng: (vp.e + vp.w) / 2 }
      : userLoc;
    const inView = (place: { lat?: number | null; lng?: number | null }) => {
      if (!vp) return true;
      const lat = Number(place.lat);
      const lng = Number(place.lng);
      return Number.isFinite(lat) && Number.isFinite(lng) && lat >= vp.s && lat <= vp.n && lng >= vp.w && lng <= vp.e;
    };
    const seen = new Set<string>();
    const next: MapSelectableFeature[] = [];
    const push = (feature: MapSelectableFeature | null | undefined) => {
      if (!feature || next.length >= 32) return;
      if (!inView(feature)) return;
      const key = `${feature.name.toLowerCase()}:${feature.lat.toFixed(4)}:${feature.lng.toFixed(4)}`;
      if (seen.has(key)) return;
      seen.add(key);
      next.push({
        ...feature,
        result_index: next.length,
        result_id: feature.result_id || stableCopilotResultId('visible', feature as unknown as Record<string, any>, next.length),
        screen_position: feature.screen_position ?? screenPositionFromBounds(feature, vp),
        confidence: feature.confidence || (feature.source === 'copilot_result' || feature.source === 'search_result' ? 'high' : 'medium'),
        aliases: feature.aliases?.length ? feature.aliases : [feature.name, feature.subtype, feature.type, feature.address].filter((item): item is string => !!item),
      });
    };
    for (const feature of visibleRenderedFeatures) push({ ...feature, result_index: next.length });
    for (const place of copilotResults) push(selectableFeatureFromPlace(place, next.length, 'copilot_result', center));
    for (const place of searchResults) push(selectableFeatureFromPlace(place, next.length, 'search_result', center));
    for (const poi of routePois) push(selectableFeatureFromPlace(poi as unknown as SearchPlace, next.length, 'trailhead_poi', center));
    if (showCampPins) {
      for (const camp of areaCamps) {
        push(selectableFeatureFromPlace({
          id: camp.id,
          name: camp.name || 'Camp',
          lat: camp.lat,
          lng: camp.lng,
          type: 'camp',
          source: camp.verified_source || camp.source_badge || camp.source || 'camp',
          source_label: camp.source_badge || camp.verified_source || camp.source || 'Camp',
          rating: camp.rating,
          rating_count: camp.rating_count,
          summary: camp.description || camp.land_type || 'Camp',
        }, next.length, 'camp', center));
      }
    }
    for (const pin of displayCommunityPins) {
      push(selectableFeatureFromPlace({
        id: String(pin.id || ''),
        name: pin.name || 'Community pin',
        lat: pin.lat,
        lng: pin.lng,
        type: pin.type || 'poi',
        source: 'community_pin',
        source_label: 'Community pin',
        summary: pin.description || 'Community map pin',
      }, next.length, 'community_pin', center));
    }
    return next.map((feature, idx) => ({ ...feature, result_index: idx }));
  }, [
    areaCamps,
    copilotResults,
    displayCommunityPins,
    placesLoadedAt,
    routePois,
    searchResults,
    showCampPins,
    userLoc?.lat,
    userLoc?.lng,
    visibleRenderedFeatures,
  ]);
  const explorePlaceCards = useMemo(() => {
    const vp = viewportRef.current;
    const center = vp
      ? { lat: (vp.n + vp.s) / 2, lng: (vp.e + vp.w) / 2 }
      : userLoc;
    return routePois
      .filter(p => (p.name && p.name.trim()) || UTILITY_PLACE_TYPES.has(String(p.type || '')))
      .filter(p => !['trail_note', 'gpx_import'].includes(String(p.type || '')))
      .sort((a, b) => {
        if (!center) return 0;
        const da = Math.hypot(a.lat - center.lat, a.lng - center.lng);
        const db = Math.hypot(b.lat - center.lat, b.lng - center.lng);
        return da - db;
      })
      .slice(0, 14);
  }, [routePois, userLoc?.lat, userLoc?.lng, mapZoom, placesLoadedAt]);
  const trailDiscoveries = useMemo(() =>
    (showTrailList || showDiscoveryPanel || discoveryMode === 'trails')
      ? buildTrailDiscoveries(
        trailSourcePois,
        trailSupportCamps,
        trailSupportFuel,
        mapReports,
        offlineSaved,
        trailDiscoveryOrigin,
        trailDiscoveryScope === 'nearby' ? 'distance' : 'score',
      )
      : [],
    [showTrailList, showDiscoveryPanel, discoveryMode, trailSourcePois, trailSupportCamps, trailSupportFuel, mapReports, offlineSaved, trailDiscoveryOrigin, trailDiscoveryScope]
  );
  const tripOverviewDays = useMemo(() => {
    if (!activeTrip) return [];
    return activeTrip.plan.daily_itinerary.map((day, idx, arr) => {
      const dayWps = waypoints.filter(w => w.day === day.day);
      const prevDay = idx > 0 ? arr[idx - 1] : null;
      const prevWps = prevDay ? waypoints.filter(w => w.day === prevDay.day) : [];
      const previousCamp = prevWps.find(w => w.type === 'camp') ?? prevWps[prevWps.length - 1] ?? null;
      const first = dayWps[0] ?? null;
      const last = dayWps[dayWps.length - 1] ?? null;
      const campWp = dayWps.find(w => w.type === 'camp') ?? null;
      const camp = (activeTrip.campsites ?? []).find(c =>
        c.recommended_day === day.day
        || c.name === campWp?.name
        || (campWp && Math.abs(c.lat - campWp.lat) < 0.001 && Math.abs(c.lng - campWp.lng) < 0.001)
      ) ?? null;
      const gasStops = (activeTrip.gas_stations ?? []).filter(g => (g as any).recommended_day === day.day);
      const poiStops = (activeTrip.route_pois ?? []).filter(p => (p as any).recommended_day === day.day);
      const timelineDay = (activeTrip.timeline ?? activeTrip.plan.timeline)?.days?.find(t => t.day === day.day) ?? null;
      const forecast = campWp
        ? cachedWeather?.forecasts?.[campWp.name] ?? Object.values(cachedWeather?.forecasts ?? {})[0]
        : null;
      return {
        day,
        waypoints: dayWps,
        previousCamp,
        first,
        last,
        camp,
        campWp,
        gasStops,
        poiStops,
        timelineDay,
        forecast,
        legMiles: dayMileageFromWaypoints(waypoints, day.day),
      };
    });
  }, [activeTrip, waypoints, cachedWeather]);
  const tripOverviewStats = useMemo(() => {
    const miles = activeTrip?.plan.total_est_miles
      ?? activeTrip?.plan.daily_itinerary.reduce((sum, day) => sum + (day.est_miles ?? 0), 0)
      ?? 0;
    return {
      miles,
      days: activeTrip?.plan.duration_days ?? activeTrip?.plan.daily_itinerary.length ?? 0,
      camps: activeTrip?.campsites?.length ?? 0,
      fuel: activeTrip?.gas_stations?.length ?? 0,
      places: activeTrip?.route_pois?.length ?? 0,
    };
  }, [activeTrip]);

  function compactRouteForPlaces(maxPoints = 96): [number, number][] {
    return compactCoords(lastRouteCoords, maxPoints);
  }

  function dayEndpointsForTripPlace(day: number) {
    const overview = tripOverviewDays.find(item => item.day.day === day);
    if (!overview) return { start: null as WP | CampsitePin | Waypoint | null, finish: null as WP | CampsitePin | Waypoint | null, legMiles: 0 };
    const start = overview.previousCamp ?? overview.first;
    const finish = overview.campWp ?? overview.camp ?? overview.last ?? overview.first;
    return { start, finish, legMiles: overview.legMiles };
  }

  function routeLegCoordsForDay(day?: number | null, maxPoints = 96): [number, number][] {
    if (!day) return compactRouteForPlaces(maxPoints);
    const { start, finish } = dayEndpointsForTripPlace(day);
    if (!start?.lat || !start?.lng || !finish?.lat || !finish?.lng) return compactRouteForPlaces(maxPoints);
    if (lastRouteCoords.length >= 2) {
      const cumulative = routeCumulativeDistances(lastRouteCoords);
      const fromProjection = projectPointToRouteProgress({ lat: start.lat, lng: start.lng }, lastRouteCoords, cumulative);
      const toProjection = projectPointToRouteProgress({ lat: finish.lat, lng: finish.lng }, lastRouteCoords, cumulative);
      if (fromProjection && toProjection) {
        const fromIdx = Math.max(0, Math.min(lastRouteCoords.length - 1, fromProjection.segmentIdx));
        const toIdx = Math.max(0, Math.min(lastRouteCoords.length - 1, toProjection.segmentIdx + 1));
        const first = Math.min(fromIdx, toIdx);
        const last = Math.max(fromIdx, toIdx);
        const slice = lastRouteCoords.slice(first, last + 1);
        const ordered = fromProjection.progressM <= toProjection.progressM ? slice : slice.reverse();
        if (ordered.length >= 2) return compactCoords(ordered, maxPoints);
      }
    }
    return [[start.lng, start.lat], [finish.lng, finish.lat]];
  }

  function tripDayNearbyFeedKey(day?: number | null) {
    if (!day) return '';
    const { start, finish } = dayEndpointsForTripPlace(day);
    if (!start?.lat || !start?.lng || !finish?.lat || !finish?.lng) return '';
    return [
      'day-leg',
      day,
      start.lat.toFixed(4),
      start.lng.toFixed(4),
      finish.lat.toFixed(4),
      finish.lng.toFixed(4),
    ].join(':');
  }

  function inferTripDayForPlace(place: { lat: number; lng: number }, explicitDay?: number | null) {
    if (explicitDay) return explicitDay;
    if ((place as any).recommended_day) return Number((place as any).recommended_day);
    if (selectedDay) return selectedDay;
    let best: { day: number; score: number } | null = null;
    for (const overview of tripOverviewDays) {
      const { start, finish } = dayEndpointsForTripPlace(overview.day.day);
      if (!start?.lat || !start?.lng || !finish?.lat || !finish?.lng) continue;
      const projection = pointSegmentProjection(place, { lat: start.lat, lng: start.lng }, { lat: finish.lat, lng: finish.lng });
      const score = projection.distance_mi + Math.abs(projection.progress - 0.5) * 2;
      if (!best || score < best.score) best = { day: overview.day.day, score };
    }
    return best?.day ?? activeTrip?.plan.daily_itinerary[0]?.day ?? 1;
  }

  function tripPlaceContextFor(place: { lat: number; lng: number; source?: string; source_label?: string; route_distance_mi?: number; route_progress?: number; route_progress_mi?: number; route_segment_index?: number }, explicitDay?: number | null): TripPlaceContext | null {
    if (!activeTrip) return null;
    const day = inferTripDayForPlace(place, explicitDay);
    const { start, finish, legMiles } = dayEndpointsForTripPlace(day);
    let routeProgress = Number.isFinite(place.route_progress as number) ? place.route_progress : undefined;
    let routeDistance = Number.isFinite(place.route_distance_mi as number) ? place.route_distance_mi : undefined;
    let routeProgressMi = Number.isFinite(place.route_progress_mi as number) ? place.route_progress_mi : undefined;
    let routeSegmentIndex = Number.isFinite(place.route_segment_index as number) ? place.route_segment_index : undefined;
    if (start?.lat && start?.lng && finish?.lat && finish?.lng) {
      const projection = pointSegmentProjection(place, { lat: start.lat, lng: start.lng }, { lat: finish.lat, lng: finish.lng });
      routeProgress = routeProgress ?? projection.progress;
      routeDistance = routeDistance ?? projection.distance_mi;
      routeProgressMi = routeProgressMi ?? (legMiles ? Math.round(legMiles * projection.progress * 10) / 10 : undefined);
    }
    const legLabel = routeProgressLabel(routeProgress);
    const bits = [
      `Day ${day}`,
      legLabel,
      routeProgressMi != null ? `${routeProgressMi.toFixed(routeProgressMi < 10 ? 1 : 0)} mi into leg` : '',
      routeDistance != null ? `${routeDistance.toFixed(1)} mi off route` : '',
    ].filter(Boolean);
    return {
      day,
      label: bits.join(' · '),
      legLabel,
      route_distance_mi: routeDistance,
      route_progress: routeProgress,
      route_progress_mi: routeProgressMi,
      route_segment_index: routeSegmentIndex,
      source: place.source_label || place.source,
    };
  }

  function tripPlaceCardMeta(place: OsmPoi, day?: number | null) {
    const context = tripPlaceContextFor(place, day);
    const source = (place as any).source_badge || place.source_label || place.attribution || place.source;
    return [
      context?.label,
      place.type?.replace(/_/g, ' '),
      !context?.route_distance_mi && (place as any).distance_mi != null ? `${Number((place as any).distance_mi).toFixed(1)} mi away` : '',
      source,
    ].filter(Boolean).join(' · ');
  }

  function tripDayNearbyCenters(day?: number) {
    const overview = tripOverviewDays.find(item => item.day.day === day);
    const { start, finish } = day ? dayEndpointsForTripPlace(day) : { start: null, finish: null };
    const legCoords = day ? routeLegCoordsForDay(day, 24) : [];
    const routeSamples = routeSamplePoints(legCoords.length >= 2 ? legCoords : lastRouteCoords, 3);
    const midpoint = start?.lat && start?.lng && finish?.lat && finish?.lng
      ? { lat: (start.lat + finish.lat) / 2, lng: (start.lng + finish.lng) / 2 }
      : null;
    const anchor = routeSamples[1] ?? midpoint ?? finish ?? overview?.camp ?? overview?.campWp ?? overview?.last ?? overview?.first ?? null;
    const vp = viewportRef.current;
    const viewportCenter = vp ? { lat: (vp.n + vp.s) / 2, lng: (vp.e + vp.w) / 2 } : null;
    const tripEnds = day ? [] : activeTrip?.plan.waypoints ?? [];
    return uniqueRouteContextCenters(
      [anchor],
      [start, midpoint, finish],
      [tripEnds[0], tripEnds[tripEnds.length - 1]],
      routeSamples,
      day ? [] : [viewportCenter, userLoc],
    );
  }

  function showPlaceAddedAlert(day: number, label: string, previousTrip: TripResult) {
    Alert.alert(
      `Added to Day ${day}`,
      label || 'Place added to this trip day.',
      [
        {
          text: 'Undo',
          style: 'destructive',
          onPress: () => {
            setActiveTrip(previousTrip);
            saveOfflineTrip(previousTrip).catch(() => {});
            setQuickToast('Place add undone');
            setTimeout(() => setQuickToast(''), 2200);
          },
        },
        { text: 'Route Builder', onPress: () => router.push('/(tabs)/route-builder') },
        { text: 'OK' },
      ],
    );
  }

  function clearCurrentRouteGeometry(tripId: string) {
    setIsRouted(false);
    setRouteSteps([]);
    setRouteLegs([]);
    setLastRouteCoords([]);
    setRouteProgress(null);
    storage.del('trailhead_active_route').catch(() => {});
    deleteRouteGeometry(tripId).catch(() => {});
  }

  function insertTripPlaceWaypoint(original: Waypoint[], waypoint: Waypoint, context: TripPlaceContext) {
    const nextWaypoints = [...original];
    const dayIndexes = original
      .map((wp, idx) => ({ wp, idx }))
      .filter(item => item.wp.day === context.day);
    if (!dayIndexes.length) {
      const previousDayLast = original.reduce((last, wp, idx) => wp.day < context.day ? idx : last, -1);
      nextWaypoints.splice(previousDayLast >= 0 ? previousDayLast + 1 : nextWaypoints.length, 0, waypoint);
      return nextWaypoints;
    }
    const { start, finish } = dayEndpointsForTripPlace(context.day);
    const targetProgress = context.route_progress ?? 0.82;
    let insertAt = dayIndexes[dayIndexes.length - 1].idx + 1;
    if (start?.lat && start?.lng && finish?.lat && finish?.lng) {
      for (const { wp, idx } of dayIndexes) {
        if (!wp.lat || !wp.lng) continue;
        if (idx === dayIndexes[0].idx && targetProgress > 0.04) continue;
        const wpProjection = pointSegmentProjection({ lat: wp.lat, lng: wp.lng }, { lat: start.lat, lng: start.lng }, { lat: finish.lat, lng: finish.lng });
        const isOvernight = wp.type === 'camp' || wp.type === 'motel' || isPlanningTargetWaypoint(wp);
        const wpProgress = isOvernight ? Math.max(wpProjection.progress, 0.96) : wpProjection.progress;
        if (wpProgress > targetProgress + 0.025) {
          insertAt = idx;
          break;
        }
      }
    } else {
      const overnightIdx = dayIndexes.find(item => item.wp.type === 'camp' || item.wp.type === 'motel' || isPlanningTargetWaypoint(item.wp));
      if (overnightIdx) insertAt = overnightIdx.idx;
    }
    nextWaypoints.splice(insertAt, 0, waypoint);
    return nextWaypoints;
  }

  function addPlaceToActiveTripDay(placeInput: Partial<Omit<OsmPoi, 'type'>> & { type?: string; name: string; lat: number; lng: number; note?: string }, dayOverride?: number | null) {
    if (!activeTrip) {
      setSearchRouteCard({ name: placeInput.name, lat: placeInput.lat, lng: placeInput.lng, dist: userLoc ? haversineKm(userLoc.lat, userLoc.lng, placeInput.lat, placeInput.lng) : null });
      setSearchMode('route_pick');
      setShowSearch(true);
      return;
    }
    const place = placeInput as OsmPoi;
    const context = tripPlaceContextFor(place, dayOverride);
    if (!context) return;
    const name = place.name || cleanDisplayLabel(place.type) || 'Place';
    const placeId = String(place.id || `${place.type || 'poi'}:${name}:${place.lat.toFixed(5)}:${place.lng.toFixed(5)}`);
    const duplicate = (activeTrip.route_pois ?? []).some(existing => {
      const sameId = String(existing.id || '') === placeId;
      const sameDay = Number((existing as any).recommended_day || 0) === context.day;
      const near = existing.lat != null && existing.lng != null
        && haversineKm(existing.lat, existing.lng, place.lat, place.lng) * 0.621371 < 0.08;
      return sameDay && (sameId || near);
    });
    if (duplicate) {
      setQuickToast(`Already on Day ${context.day}`);
      setTimeout(() => setQuickToast(''), 2200);
      return;
    }
    const routePoi: OsmPoi & { recommended_day?: number; day?: number; insert_context?: string; route_point_type?: 'side_stop' } = {
      ...place,
      id: placeId,
      name,
      type: (place.type || 'attraction') as OsmPoi['type'],
      recommended_day: context.day,
      day: context.day,
      route_point_type: 'side_stop',
      route_distance_mi: context.route_distance_mi,
      route_progress: context.route_progress,
      route_progress_mi: context.route_progress_mi,
      route_segment_index: context.route_segment_index,
      insert_context: context.label,
    };
    const waypoint: Waypoint = {
      day: context.day,
      name,
      type: 'waypoint',
      description: (place as any).summary || placeInput.note || place.address || `${placeTypeLabel(place.type)} added from Places nearby.`,
      land_type: (place as any).source_badge || place.source_label || place.source || placeTypeLabel(place.type),
      notes: [context.label, place.source_label || place.attribution || place.source].filter(Boolean).join(' · '),
      lat: place.lat,
      lng: place.lng,
      route_point_type: 'side_stop',
      verified_match: true,
      verified_source: place.source_label || place.attribution || place.source || 'Places nearby',
    };
    const previousTrip = activeTrip;
    const original = activeTrip.plan.waypoints ?? [];
    const nextWaypoints = insertTripPlaceWaypoint(original, waypoint, context);
    const recalculatedWps = nextWaypoints
      .filter(w => w.lat != null && w.lng != null && isFinite(w.lat) && isFinite(w.lng))
      .map(w => ({ ...w, lat: w.lat!, lng: w.lng! })) as WP[];
    const nextDaily = activeTrip.plan.daily_itinerary.map(d => (
      d.day === context.day || d.day === context.day + 1
        ? { ...d, est_miles: dayMileageFromWaypoints(recalculatedWps, d.day) }
        : d
    ));
    const addTimelineEvent = (timeline: TripResult['timeline'] | undefined) => {
      if (!timeline?.days) return timeline;
      return {
        ...timeline,
        days: timeline.days.map(day => {
          if (day.day !== context.day) return day;
          const exists = day.events.some(event => event.type === 'poi' && event.title === name);
          if (exists) return day;
          const event = {
            type: 'poi',
            title: name,
            description: (place as any).summary || context.label,
            day: context.day,
            source: place.source_label || place.source || 'Places nearby',
            warning_level: 'info',
            point: { lat: place.lat, lng: place.lng },
            route_position: {
              route_progress: context.route_progress,
              route_progress_mi: context.route_progress_mi,
              route_distance_mi: context.route_distance_mi,
              route_segment_index: context.route_segment_index,
            },
            quick_actions: ['navigate', 'remove', 'open_builder'],
          };
          const events = [...day.events];
          const overnightIdx = events.findIndex(existing => existing.type === 'overnight');
          events.splice(overnightIdx >= 0 ? overnightIdx : events.length, 0, event);
          return { ...day, events };
        }),
      };
    };
    const nextTimeline = addTimelineEvent(activeTrip.timeline);
    const nextPlanTimeline = addTimelineEvent(activeTrip.plan.timeline);
    const nextTrip: TripResult = {
      ...activeTrip,
      route_pois: [routePoi, ...(activeTrip.route_pois ?? [])],
      timeline: nextTimeline,
      updated_at: Date.now(),
      version: (activeTrip.version ?? 0) + 1,
      plan: {
        ...activeTrip.plan,
        waypoints: nextWaypoints,
        daily_itinerary: nextDaily,
        timeline: nextPlanTimeline,
      },
    };
    setActiveTrip(nextTrip);
    saveOfflineTrip(nextTrip).catch(() => {});
    setSelectedPlace(null);
    setSelectedPlaceContext(null);
    setSelectedPlaceTripContext(null);
    setTappedPoi(null);
    setShowPanel(true);
    setPanelCollapsed(false);
    setSelectedDay(context.day);
    setQuickToast(`Added to Day ${context.day}`);
    setTimeout(() => setQuickToast(''), 2600);
    nativeMapRef.current?.flyTo(place.lat, place.lng, 12);
    showPlaceAddedAlert(context.day, context.label, previousTrip);
  }

  useEffect(() => {
    if (!selectedCamp) return;
    loadNearbyPlacesFor(nearbyFeedKey('camp', selectedCamp.lat, selectedCamp.lng), selectedCamp, 18);
  }, [selectedCamp?.id, selectedCamp?.lat, selectedCamp?.lng]);

  useEffect(() => {
    if (!activeTrip || panelCollapsed) return;
    tripOverviewDays.forEach(({ day }) => {
      const centers = tripDayNearbyCenters(day.day);
      const center = centers[0];
      if (!center?.lat || !center?.lng) return;
      loadNearbyPlacesFor(
        tripDayNearbyFeedKey(day.day) || nearbyFeedKey('day', center.lat, center.lng),
        center,
        30,
        centers.slice(1),
        day.day,
        routeLegCoordsForDay(day.day),
      );
    });
  }, [activeTrip?.trip_id, activeTrip?.version, panelCollapsed, tripOverviewDays.length, lastRouteCoords.length]);

  const expandTripPanel = useCallback(() => {
    setShowPanel(true);
    setPanelCollapsed(false);
    Haptics.selectionAsync().catch(() => {});
  }, []);
  const collapseTripPanel = useCallback(() => {
    setShowPanel(true);
    setPanelCollapsed(true);
    Haptics.selectionAsync().catch(() => {});
  }, []);
  const restoreTripOverview = useCallback((expanded = true) => {
    if (!activeTrip || navMode) return;
    setSelectedCamp(null);
    setShowCampDetail(false);
    setSelectedPlace(null);
    setSelectedPlaceContext(null);
    setSelectedPlaceTripContext(null);
    setTappedPoi(null);
    setTappedTrail(null);
    setTappedTileSpot(null);
    setTappedGas(null);
    setSelectedCommunityPin(null);
    setSelectedTrail(null);
    setShowSearch(false);
    setSearchRouteCard(null);
    setShowPanel(true);
    setPanelCollapsed(!expanded);
    Haptics.selectionAsync().catch(() => {});
  }, [activeTrip?.trip_id, navMode]);
  const canOpenMapDrawer = !navMode && !waterFollowActive && !showSearch;
  const openMapDrawer = useCallback(() => {
    if (!canOpenMapDrawer) return;
    setShowMapDrawer(true);
    Haptics.selectionAsync().catch(() => {});
  }, [canOpenMapDrawer]);
  const collapsedPanelPan = useMemo(() => PanResponder.create({
    onStartShouldSetPanResponder: () => false,
    onMoveShouldSetPanResponder: (_, gesture) => Math.abs(gesture.dy) > 6 && Math.abs(gesture.dy) > Math.abs(gesture.dx),
    onMoveShouldSetPanResponderCapture: (_, gesture) => Math.abs(gesture.dy) > 6 && Math.abs(gesture.dy) > Math.abs(gesture.dx),
    onPanResponderTerminationRequest: () => false,
    onPanResponderRelease: (_, gesture) => {
      if (gesture.dy < -12 || gesture.vy < -0.25) expandTripPanel();
    },
  }), [expandTripPanel]);
  const expandedPanelPan = useMemo(() => PanResponder.create({
    onStartShouldSetPanResponder: () => false,
    onMoveShouldSetPanResponder: (_, gesture) => Math.abs(gesture.dy) > 6 && Math.abs(gesture.dy) > Math.abs(gesture.dx),
    onMoveShouldSetPanResponderCapture: (_, gesture) => Math.abs(gesture.dy) > 6 && Math.abs(gesture.dy) > Math.abs(gesture.dx),
    onPanResponderTerminationRequest: () => false,
    onPanResponderRelease: (_, gesture) => {
      if (gesture.dy > 12 || gesture.vy > 0.25) collapseTripPanel();
    },
  }), [collapseTripPanel]);
  const pinList = useMemo(() =>
    displayCommunityPins.map(p => ({ lat: p.lat, lng: p.lng, name: p.name, type: p.type })),
    [displayCommunityPins]
  );

  const centerLat = waypoints[0]?.lat ?? 39.5;
  const centerLng = waypoints[0]?.lng ?? -98.5;

  const mapHtml = useMemo(() =>
    buildMapHtml(centerLat, centerLng, waypoints, campsites, gas, pinList),
    [centerLat, centerLng, waypoints, campsites, gas, pinList]
  );

  // ── Nav HUD values ──────────────────────────────────────────────────────────

  const navTarget = navMode ? (waypoints[navIdx] ?? navDest ?? null) : null;
  const distKm    = userLoc && navTarget ? haversineKm(userLoc.lat, userLoc.lng, navTarget.lat, navTarget.lng) : null;
  const bearing   = userLoc && navTarget ? calcBearing(userLoc.lat, userLoc.lng, navTarget.lat, navTarget.lng) : null;
  const speedMph  = userSpeed !== null && userSpeed > 0 ? userSpeed * 2.237 : null;
  const selectedTrailRoutePlan = trailRoutePlans.find(p => p.id === selectedTrailRoutePlanId) ?? trailRoutePlans[0] ?? null;
  const previewTrailDistanceM = selectedTrailRoutePlan?.distanceM ?? (trailTraceRoute.length > 1 ? trailCoordsDistanceM(trailTraceRoute) : 0);
  const elevationHydrationRef = useRef<Set<string>>(new Set());
  useEffect(() => {
    trailRoutePlans.forEach(plan => {
      if (plan.elevationConfidence && plan.elevationConfidence !== 'unavailable') return;
      const key = `${plan.id}:${Math.round(plan.distanceM)}:${plan.coords.length}`;
      if (elevationHydrationRef.current.has(key)) return;
      elevationHydrationRef.current.add(key);
      hydrateTrailRoutePlanElevation(plan);
    });
  }, [trailRoutePlans]);
  const routeCumulative = useMemo(() => routeCumulativeDistances(lastRouteCoords), [lastRouteCoords]);
  const activeRouteProgress = routeProgress;
  // Current step the user is navigating toward
  const nextStep = routeSteps[stepIdx] ?? null;
  const afterStep = routeSteps[stepIdx + 1] ?? null;
  const speedLimitMph = nextStep?.speedLimit ? Math.round(nextStep.speedLimit * 0.621371) : null;
  const stepRouteProgress = useMemo(() => {
    if (!activeRouteProgress || !nextStep || nextStep.lat == null || nextStep.lng == null || lastRouteCoords.length < 2) return null;
    return projectPointToRouteProgress({ lat: nextStep.lat, lng: nextStep.lng }, lastRouteCoords, routeCumulative);
  }, [activeRouteProgress, nextStep, lastRouteCoords, routeCumulative]);
  // Real distance to the step's maneuver point (more accurate than step.distance)
  const routeStepDistM = activeRouteProgress && stepRouteProgress
    ? stepRouteProgress.progressM - activeRouteProgress.distanceM
    : null;
  const directStepDistM = nextStep?.lat != null && userLoc
    ? haversineKm(userLoc.lat, userLoc.lng, nextStep.lat!, nextStep.lng!) * 1000
    : null;
  const stepDistM = routeStepDistM !== null && routeStepDistM >= -25
    ? Math.max(0, routeStepDistM)
    : directStepDistM;
  const isProceeding = activeRouteProgress
    ? activeRouteProgress.distanceM < 120 && activeRouteProgress.deviationM > 90
    : distKm !== null && distKm > 30;
  const proceedToRoute = !isRerouting && isRouted && !!activeRouteProgress && activeRouteProgress.distanceM < 120 && activeRouteProgress.deviationM > 90;
  // Step-based ETA: remaining seconds = time to reach current maneuver + sum of later step durations
  const etaMins = useMemo(() => {
    if (!navMode || !userSpeed || userSpeed < 0.5) return null;
    const curStepSecs = stepDistM != null ? stepDistM / userSpeed : (nextStep?.duration ?? 0);
    const laterSecs = routeSteps.slice(stepIdx + 1).reduce((sum, s) => sum + (s.duration || 0), 0);
    return Math.round((curStepSecs + laterSecs) / 60);
  }, [navMode, userSpeed, stepDistM, stepIdx, routeSteps]);

  // Total remaining trip distance (current → navIdx → ... → last waypoint)
  const remainingKm = useMemo(() => {
    if (activeRouteProgress && activeRouteProgress.routeDistanceM > 0) return activeRouteProgress.remainingM / 1000;
    if (!navMode || !userLoc || !waypoints.length) return null;
    let total = distKm ?? 0;
    for (let i = navIdx; i < waypoints.length - 1; i++) {
      total += haversineKm(waypoints[i].lat, waypoints[i].lng, waypoints[i + 1].lat, waypoints[i + 1].lng);
    }
    return total;
  }, [activeRouteProgress, navMode, navIdx, distKm, userLoc, waypoints]);

  function toggleDataLayer(key: string, val: boolean) {
    webRef.current?.postMessage(JSON.stringify({ type: 'set_layer', layer: key, show: val }));
  }

  function toggleLandOverlay(val: boolean) {
    setShowLands(val);
    webRef.current?.postMessage(JSON.stringify({ type: 'set_land_overlay', show: val }));
  }

  function toggleUsgsOverlay(val: boolean) {
    setShowUsgs(val);
    webRef.current?.postMessage(JSON.stringify({ type: 'set_usgs_overlay', show: val }));
  }

  function togglePoiOverlay(val: boolean) {
    setShowPois(val);
    if (val) {
      const vp = viewportRef.current;
      const center = vp
        ? { lat: (vp.n + vp.s) / 2, lng: (vp.e + vp.w) / 2 }
        : userLoc ?? (waypoints[0] ? { lat: waypoints[0].lat, lng: waypoints[0].lng } : null);
      if (center) fetchPois(center);
    }
  }

  function manualReroute() {
    if (!userLoc || !navMode) return;
    const now = Date.now();
    if (isReroutingRef.current || now - lastRerouteRef.current < 5000) return;
    lastRerouteRef.current = now;
    setIsRerouting(true);
    isReroutingRef.current = true;
    setRouteProgress(null);
    if (USE_IOS_NATIVE_NAV_ENGINE) stopNavigationSession().catch(() => {});
    webRef.current?.postMessage(JSON.stringify({
      type: 'reroute_from',
      lat: userLoc.lat, lng: userLoc.lng,
      fromIdx: navRef.current.idx,
    }));
    nativeMapRef.current?.rerouteFrom(userLoc.lat, userLoc.lng, navRef.current.idx);
    setRouteLegOffset(navRef.current.idx);
    safeSpeech('Recalculating.', { rate: 0.95 });
  }

  function focusNavigationCamera(loc = userLoc) {
    if (!loc) return;
    setNavCameraFollow(true);
    const hdg = smoothedHdgRef.current ?? userHeading ?? -1;
    webRef.current?.postMessage(JSON.stringify({
      type: 'nav_center',
      lat: loc.lat,
      lng: loc.lng,
      heading: hdg,
      zoom: 17,
      speed: userSpeedRef.current,
    }));
    nativeMapRef.current?.flyTo(loc.lat, loc.lng, 17);
  }

  function endNavigation() {
    stopTrailheadVoice();
    stopNavigationSession().catch(() => {});
    nativeMapRef.current?.stopNavigation();
    setNavCameraFollow(false);
    setNavMode(false);
    setShowSteps(false);
    navRef.current.active = false;
    setIsApproaching(false);
    setIsRerouting(false);
    isReroutingRef.current = false;
    setOffRouteWarn(false);
    setApproachingReport(null);
    setRouteProgress(null);
    setNavDest(null);
    navDestRef.current = null;
    stepAnnouncedRef.current.clear();
    alertedRepIdsRef.current.clear();
    if (offRouteWarnTimer.current) {
      clearTimeout(offRouteWarnTimer.current);
      offRouteWarnTimer.current = null;
    }
    if (rerouteTimeoutRef.current) {
      clearTimeout(rerouteTimeoutRef.current);
      rerouteTimeoutRef.current = null;
    }
    if (approachDismissRef.current) {
      clearTimeout(approachDismissRef.current);
      approachDismissRef.current = null;
    }
  }

  const routeSegmentEndIndex = useCallback((fromIdx: number) => {
    if (!waypoints.length) return fromIdx;
    const start = Math.max(0, Math.min(fromIdx, waypoints.length - 1));
    const startDay = waypoints[start]?.day;
    let end = start;
    for (let i = start + 1; i < waypoints.length; i += 1) {
      if (waypoints[i]?.day !== startDay) break;
      end = i;
    }
    return Math.min(end, start + 8, waypoints.length - 1);
  }, [waypoints]);

  function startDayNav(day: number | 'all', fromIdx?: number) {
    if (navMode) endNavigation();
    setRouteProgress(null);
    setIsRerouting(false);
    isReroutingRef.current = false;
    setShowDayModal(false);
    setTappedWp(null);
    if (day === 'all') {
      setNavIdx(fromIdx ?? 0);
      navRef.current.idx = fromIdx ?? 0;
    } else {
      const firstOfDay = waypoints.findIndex(w => w.day === day);
      const idx = fromIdx !== undefined ? fromIdx : (firstOfDay >= 0 ? firstOfDay : 0);
      setNavIdx(idx);
      navRef.current.idx = idx;
    }
    setNavMode(true);
    focusNavigationCamera();
    setShowSearch(false);
  }

  function openInMaps() {
    const navWaypoints = waypoints.filter(w => w.route_point_type !== 'side_stop');
    if (!navWaypoints.length) return;
    const origin = `${navWaypoints[0].lat},${navWaypoints[0].lng}`;
    const dest   = `${navWaypoints[navWaypoints.length - 1].lat},${navWaypoints[navWaypoints.length - 1].lng}`;
    const mids   = navWaypoints.slice(1, -1).slice(0, 8).map(w => `${w.lat},${w.lng}`).join('|');
    const url    = `https://www.google.com/maps/dir/?api=1&origin=${origin}&destination=${dest}${mids ? `&waypoints=${encodeURIComponent(mids)}` : ''}&travelmode=driving`;
    Linking.openURL(url).catch(() =>
      Linking.openURL(`maps://?saddr=${origin}&daddr=${dest}`).catch(() => {})
    );
  }

  function navigateToCamp(camp: { lat: number; lng: number; name: string }) {
    setShowCampDetail(false);
    if (!userLoc) {
      Alert.alert('Location Needed', 'Enable location services to navigate.');
      return;
    }
    previewSearchRoute(
      { name: 'My Location', lat: userLoc.lat, lng: userLoc.lng, isCurrentLocation: true },
      { lat: camp.lat, lng: camp.lng, name: camp.name, type: 'camp' },
    );
    setSearchMode('route_pick');
    setShowSearch(true);
  }

  function openTrailFeature(feature: TrailFeature) {
    focusMapSelectionPoint({ lat: feature.lat, lng: feature.lng, name: feature.name }, 13, 'trail');
    setSelectedTrailProfile(null);
    setTrailRouteBuilderOpen(false);
    setSavedTrailRouteOpenId(null);
    setTrailRoutePlans([]);
    setSelectedTrailRoutePlanId(null);
    setTrailRouteBuilderError('');
    setTrailSnapFailureReason('');
    setTrailRouteSegmentStatus([]);
    setTrailFieldReports([]);
    setTrailFieldReportSummary(null);
    setShowTrailFieldReportForm(false);
    resetFieldReportForm();
    setTrailCardCollapsed(false);
    setSelectedTrail(null);
    setSelectedPlace({
      id: feature.profile_id || `trail:${feature.lat.toFixed(5)}:${feature.lng.toFixed(5)}`,
      name: feature.name,
      lat: feature.lat,
      lng: feature.lng,
      type: feature.type || 'trail',
      subtype: feature.subtitle,
      source: feature.profile_id ? 'trailhead' : 'map',
      source_label: feature.profile_id ? 'Trailhead trail' : 'Map trail',
      provider_place_id: feature.profile_id,
      photo_url: feature.photo_url || null,
      summary: feature.summary || 'Mapped trail route with nearby support context from Trailhead.',
    });
    setSelectedCamp(null);
    setTappedTrail(null);
    setTappedTileSpot(null);
    setTappedGas(null);
    setTappedPoi(null);
    setSelectedCommunityPin(null);
    const id = trailReportId(feature);
    api.getTrailFieldReports(id).then(setTrailFieldReports).catch(() => {});
    api.getTrailFieldReportSummary(id).then(setTrailFieldReportSummary).catch(() => {});
    if (feature.profile_id) {
      api.getTrailProfile(feature.profile_id)
        .then(profile => {
          setSelectedTrailProfile(profile);
          setSelectedPlace(current => current && current.id === feature.profile_id ? {
            ...current,
            name: profile.name || current.name,
            summary: profile.summary || current.summary,
            photo_url: profile.photos?.[0]?.url || current.photo_url,
            photos: profile.photos?.map(photo => ({ ...photo, url: photo.url })),
            source_label: profile.source_label || current.source_label,
          } : current);
          if (profile.field_report_summary) setTrailFieldReportSummary(profile.field_report_summary);
        })
        .catch(() => {});
    }
  }

  function openTrailFromPoint(name: string, lat: number, lng: number, cls = 'path') {
    const support = buildTrailSupport(
      { lat, lng },
      trailSupportCamps,
      trailSupportFuel,
      allMapPois,
      mapReports,
      offlineSaved,
    );
    openTrailFeature(featureFromMapTrail(name, lat, lng, cls, support));
  }

  function mapTileCampPin(name: string, kind: string, lat: number, lng: number, landType?: string): CampsitePin {
    const cleanKind = String(kind || 'camp_site');
    const title = name || (cleanKind === 'camp_pitch' ? 'Dispersed Camping Spot' : cleanKind === 'shelter' ? 'Trail Shelter' : 'Campground');
    const group = /\bgroup\b/i.test(title) || /\b(group|camp_area)\b/i.test(cleanKind);
    const dispersed = cleanKind === 'camp_pitch';
    const shelter = cleanKind === 'shelter';
    return {
      id: `tile:${cleanKind}:${lat.toFixed(5)}:${lng.toFixed(5)}`,
      name: title,
      lat,
      lng,
      tags: [
        group ? 'group' : '',
        dispersed ? 'dispersed' : shelter ? 'shelter' : 'campground',
      ].filter(Boolean),
      land_type: landType || (dispersed ? 'Dispersed' : shelter ? 'Shelter' : 'Campground'),
      description: 'Map-sourced camp feature. Verify current access, rules, road conditions, and stay limits before relying on it.',
      reservable: false,
      cost: '',
      url: '',
      ada: false,
      source: 'map_tile',
      verified_source: 'Map tile',
    };
  }

  function campTileNameToken(value: string) {
    return value.toLowerCase().replace(/\b(campground|camp ground|camp|campsite|camp site|site|area|rv|park|dispersed|spot|shelter)\b/g, ' ').replace(/[^a-z0-9]/g, '');
  }

  function strictBackendCampMatch(tapped: Pick<CampsitePin, 'name' | 'lat' | 'lng'>, results: CampsitePin[]) {
    const tappedToken = campTileNameToken(tapped.name || '');
    const usable = results
      .filter(camp => Number.isFinite(camp.lat) && Number.isFinite(camp.lng))
      .map(camp => ({
        camp,
        distanceKm: haversineKm(tapped.lat, tapped.lng, camp.lat, camp.lng),
        token: campTileNameToken(camp.name || ''),
      }))
      .filter(item => Number.isFinite(item.distanceKm));
    const named = usable
      .filter(item => {
        if (item.distanceKm > 0.5) return false;
        if (tappedToken.length < 5 || item.token.length < 5) return false;
        return item.token.includes(tappedToken.slice(0, 10)) || tappedToken.includes(item.token.slice(0, 10));
      })
      .sort((a, b) => a.distanceKm - b.distanceKm)[0];
    if (named) return named.camp;
    const coordinateExact = usable
      .filter(item => item.distanceKm <= 0.08)
      .sort((a, b) => a.distanceKm - b.distanceKm)[0];
    return coordinateExact?.camp ?? null;
  }

  function openMapTileCamp(name: string, kind: string, lat: number, lng: number, landType?: string) {
    const pin = mapTileCampPin(name, kind, lat, lng, landType);
    setTappedPoi(null);
    setTappedGas(null);
    setTappedTrail(null);
    setTappedTileSpot(null);
    setSelectedPlace(null);
    setSelectedTrail(null);
    setSelectedCommunityPin(null);
    setSelectedCamp(pin);
    setCampDetail(null);
    setCampInsight(null);
    setWikiArticles([]);
    setCampFullness(null);
    setCampWeather(null);
    if (pin.id) api.getCampFullness(pin.id).then(r => setCampFullness(r)).catch(() => {});
    api.getWeather(lat, lng, 3, weatherUnitMode).then(r => {
      if (selectedCampRef.current?.id === pin.id) setCampWeather(r);
    }).catch(() => {});

    api.getNearbyCamps(lat, lng, 2).then(results => {
      if (!results.length) return;
      const match = strictBackendCampMatch(pin, results);
      if (!match) return;
      setSelectedCamp(prev => prev?.id === pin.id ? match : prev);
      if (match?.id) api.getCampFullness(match.id).then(r => setCampFullness(r)).catch(() => {});
    }).catch(() => {});
  }

  function renderedMapboxPlaceKey(place: Pick<SearchPlace, 'id' | 'name' | 'lat' | 'lng' | 'place_id' | 'provider_place_id'>) {
    return String(place.id || place.place_id || place.provider_place_id || `${place.name}:${place.lat.toFixed(5)}:${place.lng.toFixed(5)}`);
  }

  function cancelRenderedMapboxEnrichment({ clearRecent = true }: { clearRecent?: boolean } = {}) {
    renderedMapboxEnrichmentSeqRef.current += 1;
    if (renderedMapboxEnrichmentTimerRef.current) {
      clearTimeout(renderedMapboxEnrichmentTimerRef.current);
      renderedMapboxEnrichmentTimerRef.current = null;
    }
    if (clearRecent) recentRenderedMapboxSelectionRef.current = null;
  }

  function shouldIgnoreRecentRenderedMapboxFallbackTap(lat?: number, lng?: number) {
    const recent = recentRenderedMapboxSelectionRef.current;
    if (!recent || Date.now() - recent.at > 2500) return false;
    if (lat == null || lng == null || !Number.isFinite(lat) || !Number.isFinite(lng)) return true;
    const distanceKm = haversineKm(lat, lng, recent.lat, recent.lng);
    return Number.isFinite(distanceKm) && distanceKm < 0.18;
  }

  function scheduleRenderedMapboxEnrichment(place: SearchPlace, feature: MapSelectableFeature) {
    const key = renderedMapboxPlaceKey(place);
    const seq = ++renderedMapboxEnrichmentSeqRef.current;
    if (renderedMapboxEnrichmentTimerRef.current) clearTimeout(renderedMapboxEnrichmentTimerRef.current);
    renderedMapboxEnrichmentTimerRef.current = setTimeout(() => {
      renderedMapboxEnrichmentTimerRef.current = null;
      InteractionManager.runAfterInteractions(() => {
        if (renderedMapboxEnrichmentSeqRef.current !== seq) return;
        enrichRenderedFeaturePlace(feature).then(enriched => {
          if (renderedMapboxEnrichmentSeqRef.current !== seq) return;
          setSelectedPlace(current => {
            if (!current || renderedMapboxPlaceKey(current) !== key) return current;
            return { ...current, ...enriched };
          });
        }).catch(() => {});
      });
    }, 700);
  }

  function openPoiFeature(poi: OsmPoi, day?: number | null) {
    if (mapTapToolOwnsFeatureSelection) return;
    const place = poi as SearchPlace;
    const source = String(poi.source || '').toLowerCase();
    const renderedMapbox = isRenderedMapboxPlaceSource(source);
    cancelRenderedMapboxEnrichment({ clearRecent: !renderedMapbox });
    const nextPlace = {
      ...place,
      source: place.source || 'map',
      source_label: place.source_label || place.source_badge || 'Map source',
      summary: renderedMapbox
        ? place.summary || place.address
        : place.summary || place.address || `${cleanDisplayLabel(place.type || 'place')} selected from the map.`,
    } as SearchPlace;
    if (renderedMapbox) {
      recentRenderedMapboxSelectionRef.current = {
        at: Date.now(),
        lat: nextPlace.lat,
        lng: nextPlace.lng,
        key: renderedMapboxPlaceKey(nextPlace),
      };
    }
    setTappedPoi(null);
    setShowSearch(false);
    setShowDiscoveryPanel(false);
    setCopilotResults([]);
    setCopilotResultScope(null);
    setSearchResults([]);
    setSearchRouteCard(null);
    setSelectedPlaceTripContext(tripPlaceContextFor(poi, day));
    setSelectedPlace(nextPlace);
    setSelectedCamp(null);
    setTappedTrail(null);
    setTappedTileSpot(null);
    setTappedGas(null);
    setSelectedCommunityPin(null);
    setSelectedTrail(null);
    if (renderedMapbox) {
      const feature = selectableFeatureFromPlace(nextPlace, 0, source, userLoc ?? null);
      if (feature) scheduleRenderedMapboxEnrichment(nextPlace, feature);
    }
  }

  function nearbyFeedKey(prefix: string, lat?: number | null, lng?: number | null) {
    if (lat == null || lng == null || !isFinite(lat) || !isFinite(lng)) return '';
    return `${prefix}:${lat.toFixed(3)}:${lng.toFixed(3)}`;
  }

  function openNearbyPlace(place: OsmPoi, day?: number | null) {
    setSelectedCamp(null);
    setShowCampDetail(false);
    setShowPanel(false);
    setPanelCollapsed(true);
    setShowSearch(false);
    setSearchRouteCard(null);
    openPoiFeature(place, day);
    nativeMapRef.current?.flyTo(place.lat, place.lng, 12);
    webRef.current?.postMessage(JSON.stringify({ type: 'fly_to', lat: place.lat, lng: place.lng, name: place.name }));
  }

  function openTripPlacesSearch(day?: number) {
    setSelectedDay(day ?? null);
    const centers = tripDayNearbyCenters(day);
    const anchor = centers[0] ?? null;
    const legRoute = day ? routeLegCoordsForDay(day) : compactRouteForPlaces();
    const feedKey = day ? tripDayNearbyFeedKey(day) : '';
    if (anchor?.lat && anchor?.lng) {
      loadNearbyPlacesFor(feedKey || nearbyFeedKey('day', anchor.lat, anchor.lng), anchor, 30, centers.slice(1), day, legRoute);
      nativeMapRef.current?.flyTo(anchor.lat, anchor.lng, 11);
    }
    setShowPanel(true);
    setPanelCollapsed(false);
    setShowSearch(false);
  }

  function renderNearbyPlaceCard(place: OsmPoi, compact = false, day?: number | null) {
    const photo = nearbyPlacePhoto(place);
    const meta = tripPlaceCardMeta(place, day);
    const canAddToTrip = !!activeTrip;
    return (
      <TouchableOpacity key={place.id || `${place.type}:${place.lat}:${place.lng}`} style={[s.nearbyPlaceCard, compact && s.nearbyPlaceCardCompact]} onPress={() => openNearbyPlace(place, day)} activeOpacity={0.86}>
        {photo ? (
          <Image source={{ uri: photo }} style={s.nearbyPlacePhoto} resizeMode="cover" />
        ) : (
          <View style={s.nearbyPlaceIconBlock}>
            <Ionicons name={placeTypeIcon(place.type) as any} size={18} color={C.orange} />
          </View>
        )}
        {canAddToTrip ? (
          <TouchableOpacity
            style={s.nearbyPlaceAdd}
            onPress={() => addPlaceToActiveTripDay(place, day)}
            hitSlop={{ top: 8, bottom: 8, left: 8, right: 8 }}
          >
            <Ionicons name="add" size={16} color="#fff" />
          </TouchableOpacity>
        ) : null}
        <View style={s.nearbyPlaceBody}>
          <Text style={s.nearbyPlaceName} numberOfLines={2}>{place.name || cleanDisplayLabel(place.type) || 'Place'}</Text>
          <Text style={s.nearbyPlaceMeta} numberOfLines={2}>{meta}</Text>
        </View>
      </TouchableOpacity>
    );
  }

  function nearbyPlacePhoto(place: Partial<OsmPoi> | null | undefined) {
    const photos = (place as any)?.photos;
    const first = Array.isArray(photos) ? photos[0] : null;
    return mediaUrl((place as any)?.photo_url || (typeof first === 'string' ? first : first?.url));
  }

  function loadNearbyPlacesFor(
    key: string,
    center?: { lat?: number | null; lng?: number | null },
    radius = 22,
    fallbackCenters: Array<{ lat?: number | null; lng?: number | null }> = [],
    day?: number | null,
    routeOverride?: [number, number][],
  ) {
    if (!key || center?.lat == null || center?.lng == null || !isFinite(center.lat) || !isFinite(center.lng)) return;
    if (extremeMapLayerActive) {
      setNearbyPlaceFeeds(prev => ({
        ...prev,
        [key]: { loading: false, places: [], error: undefined, loadedAt: Date.now() },
      }));
      return;
    }
    const cached = nearbyPlaceFeeds[key];
    if (cached?.loadedAt && Date.now() - cached.loadedAt < 5 * 60_000) return;
    setNearbyPlaceFeeds(prev => ({
      ...prev,
      [key]: { loading: true, places: prev[key]?.places ?? [], loadedAt: prev[key]?.loadedAt },
    }));
    const categories = placeCategoryRequest(DEFAULT_PLACE_FILTERS, true);
    const allowedPlaceFilters = new Set(categories.split(',').map(item => item.trim()).filter(Boolean));
    const primaryCenter = { lat: center.lat, lng: center.lng };
    const centers = uniqueRouteContextCenters(
      [primaryCenter],
      fallbackCenters
        .filter(point => point.lat != null && point.lng != null && isFinite(point.lat) && isFinite(point.lng))
        .map(point => ({ lat: point.lat!, lng: point.lng! })),
    );
    const route = routeOverride?.length ? routeOverride : (day ? routeLegCoordsForDay(day) : compactRouteForPlaces());
    const scopeOptions = day
      ? { scope_id: key, recommended_day: day, route_scope: 'leg' as const }
      : {};
    const normalize = (places: OsmPoi[]) => places
      .filter(p => String(p.type) !== 'camp')
      .filter(p => !isLowValueGenericBlmPlace(p, isTripServicePlace(p)))
      .filter(p => (p.name && p.name.trim()) || UTILITY_PLACE_TYPES.has(String(p.type || '')))
      .map(p => {
        const context = day ? tripPlaceContextFor(p, day) : null;
        return context ? {
          ...p,
          recommended_day: context.day,
          day: context.day,
          route_distance_mi: context.route_distance_mi ?? p.route_distance_mi,
          route_progress: context.route_progress ?? p.route_progress,
          route_progress_mi: context.route_progress_mi ?? p.route_progress_mi,
          route_segment_index: context.route_segment_index ?? p.route_segment_index,
        } as OsmPoi : p;
      });
    const merge = (batches: OsmPoi[][]) => {
      const seen = new Set<string>();
      const merged: OsmPoi[] = [];
      batches.flat().forEach(place => {
        if (!place?.lat || !place?.lng) return;
        const type = place.type || 'poi';
        const key = String(place.id || `${type}:${(place.name || '').toLowerCase()}:${place.lat.toFixed(4)}:${place.lng.toFixed(4)}`);
        const fuzzy = `${type}:${(place.name || '').toLowerCase().replace(/[^a-z0-9]/g, '').slice(0, 32)}:${place.lat.toFixed(3)}:${place.lng.toFixed(3)}`;
        if (seen.has(key) || seen.has(fuzzy)) return;
        seen.add(key); seen.add(fuzzy);
        merged.push(place);
      });
      return merged
        .filter(place => !isLowValueGenericBlmPlace(place, isTripServicePlace(place)))
        .sort((a, b) => {
          const ac = tripPlaceContextFor(a, day);
          const bc = tripPlaceContextFor(b, day);
          const ad = ac?.route_progress_mi ?? (a as any).distance_mi ?? a.route_distance_mi ?? 999;
          const bd = bc?.route_progress_mi ?? (b as any).distance_mi ?? b.route_distance_mi ?? 999;
          return ad - bd;
        })
        .slice(0, 18);
    };
    const offlineFallbackPlaces = merge(centers.map(point => normalize(
      offlinePlacePois
        .filter(p => p.lat != null && p.lng != null && isFinite(p.lat) && isFinite(p.lng))
        .filter(p => placeMatchesFilters(p, allowedPlaceFilters))
        .map(p => ({
          ...p,
          source: p.source || 'offline',
          source_label: p.source_label || 'Offline pack',
          distance_mi: typeof (p as any).distance_mi === 'number' ? (p as any).distance_mi : haversineKm(point.lat!, point.lng!, p.lat, p.lng) * 0.621371,
        }))
        .filter(p => (p.distance_mi ?? 999) <= Math.max(radius + 6, 14))
    )));
    Promise.allSettled(
      centers.map(point => api.getNearbySmartPack(point.lat!, point.lng!, radius, categories, route, scopeOptions).then(pack => normalize((pack.places ?? []) as OsmPoi[])))
    ).then(async smartResults => {
      const smartPlaces = merge(smartResults.flatMap(result => result.status === 'fulfilled' ? [result.value] : []));
      if (smartPlaces.length >= 6) return { places: smartPlaces, sourceLabel: undefined as string | undefined };
      if (smartPlaces.length) {
        return {
          places: offlineFallbackPlaces.length ? merge([smartPlaces, offlineFallbackPlaces]) : smartPlaces,
          sourceLabel: offlineFallbackPlaces.length ? 'Expanded with downloaded place packs' : undefined,
        };
      }
      const nearbyResults = await Promise.allSettled(
        centers.map(point => api.getNearbyPlaces(point.lat!, point.lng!, radius, categories, 'auto').then(places => normalize(places)))
      );
      const nearby = merge(nearbyResults.flatMap(result => result.status === 'fulfilled' ? [result.value] : []));
      if (nearby.length >= 6) return { places: nearby, sourceLabel: undefined as string | undefined };
      if (nearby.length) {
        return {
          places: offlineFallbackPlaces.length ? merge([nearby, offlineFallbackPlaces]) : nearby,
          sourceLabel: offlineFallbackPlaces.length ? 'Expanded with downloaded place packs' : undefined,
        };
      }
      const osmPlaces = await api.getOsmPois(center.lat!, center.lng!, radius, 'trailhead,viewpoint,peak,hot_spring,water,fuel,parking')
        .then(places => normalize(places))
        .catch(() => []);
      if (osmPlaces.length) {
        return {
          places: offlineFallbackPlaces.length ? merge([osmPlaces, offlineFallbackPlaces]) : osmPlaces,
          sourceLabel: offlineFallbackPlaces.length ? 'Expanded with downloaded place packs' : undefined,
        };
      }
      if (offlineFallbackPlaces.length) {
        return { places: offlineFallbackPlaces, sourceLabel: 'Downloaded place packs' };
      }
      return { places: [] as OsmPoi[], sourceLabel: undefined as string | undefined };
    }).then(({ places, sourceLabel }) => {
      setNearbyPlaceFeeds(prev => ({
        ...prev,
        [key]: {
          loading: false,
          places,
          error: places.length ? undefined : 'No nearby place cards loaded yet. Try a wider search from the map.',
          loadedAt: Date.now(),
          sourceLabel,
        },
      }));
    }).catch(() => {
      setNearbyPlaceFeeds(prev => ({ ...prev, [key]: { loading: false, places: prev[key]?.places ?? [], error: 'Places unavailable right now. Try this area again.', loadedAt: Date.now() } }));
    });
  }

  function searchCampsNearTrail(trail: TrailFeature) {
    const bounds = { n: trail.lat + 0.35, s: trail.lat - 0.35, e: trail.lng + 0.35, w: trail.lng - 0.35, zoom: 11 };
    setQuickToast('Searching camps near trail');
    setTimeout(() => setQuickToast(''), 2500);
    setTimeout(() => {
      viewportRef.current = bounds;
      nativeMapRef.current?.flyTo(trail.lat, trail.lng, 11);
      setShowDiscoveryPanel(false);
      setShowLayerSheet(false);
      setTimeout(() => loadCampsInArea(bounds, activeFilters), 120);
    }, 220);
  }

  async function runTrailDiscoverySearch(scope: TrailDiscoveryScope = 'view') {
    if (isSearchingTrails) return;
    setTrailDiscoveryScope(scope);
    const visibleBounds = scope === 'view'
      ? await nativeMapRef.current?.getVisibleBounds?.().catch(() => null)
      : null;
    const vp = visibleBounds ?? viewportRef.current;
    const visibleCenter = visibleBounds
      ? [((visibleBounds.e + visibleBounds.w) / 2), ((visibleBounds.n + visibleBounds.s) / 2)] as [number, number]
      : await nativeMapRef.current?.getVisibleCenter?.().catch(() => null);
    const mapCenter = scope === 'nearby'
      ? (userLoc ? [userLoc.lng, userLoc.lat] as [number, number] : visibleCenter ?? currentMapCenterCoord())
      : visibleCenter ?? currentMapCenterCoord();
    const center = mapCenter
        ? { lat: mapCenter[1], lng: mapCenter[0] }
        : vp
          ? { lat: (vp.n + vp.s) / 2, lng: (vp.e + vp.w) / 2 }
          : userLoc;
    if (center) {
      setTrailDiscoveryOrigin(scope === 'nearby' && userLoc ? { lat: userLoc.lat, lng: userLoc.lng } : center);
      setIsSearchingTrails(true);
      setQuickToast(scope === 'nearby' && userLoc ? 'Finding trails near you' : 'Finding trails in this map view');
      try {
        const radiusMi = scope === 'nearby'
          ? 45
          : vp
          ? Math.max(3, Math.min(80, Math.max(
              Math.abs(vp.n - vp.s) * 69,
              Math.abs(vp.e - vp.w) * 69 * Math.cos(center.lat * Math.PI / 180),
            ) / 2 + 3))
          : 45;
        let live: OsmPoi[] = [];
        try {
          const discovered = await api.discoverTrails({
            mode: scope,
            lat: center.lat,
            lng: center.lng,
            radius: radiusMi,
            n: scope === 'view' ? vp?.n : undefined,
            s: scope === 'view' ? vp?.s : undefined,
            e: scope === 'view' ? vp?.e : undefined,
            w: scope === 'view' ? vp?.w : undefined,
            limit: 80,
          });
          live = (discovered.trails ?? []).map(trailProfileToPoi);
          setQuickToast(discovered.offline ? 'Showing offline trail results' : scope === 'nearby' && userLoc ? 'Trails near you loaded' : 'Trails in this view loaded');
        } catch {
          live = await api.getOsmPois(center.lat, center.lng, Math.min(80, Math.max(radiusMi, 30)), 'trail,trailhead,viewpoint,peak,hot_spring,water');
          setQuickToast(scope === 'nearby' && userLoc ? 'Showing live map trail places' : 'Showing map-view trail places');
        }
        const supportRadiusMi = Math.min(75, Math.max(radiusMi, 30));
        const [supportPoisResult, supportGasResult, supportCampsResult] = await Promise.allSettled([
          api.getOsmPois(center.lat, center.lng, supportRadiusMi, 'water,trailhead,viewpoint,peak,hot_spring'),
          api.getGas(center.lat, center.lng, supportRadiusMi),
          api.getNearbyCamps(center.lat, center.lng, supportRadiusMi, activeFilters),
        ]);
        const onlineSupportPois = supportPoisResult.status === 'fulfilled' ? supportPoisResult.value : [];
        const onlineFuelPois = supportGasResult.status === 'fulfilled'
          ? supportGasResult.value.map(gasStationToPoi).filter((poi): poi is OsmPoi => !!poi)
          : [];
        if (supportCampsResult.status === 'fulfilled') {
          setAreaCamps(supportCampsResult.value.slice(0, 180));
          webRef.current?.postMessage(JSON.stringify({ type: 'set_camps', pins: supportCampsResult.value.slice(0, 180) }));
        }
        const padLat = vp ? Math.max(0.02, Math.abs(vp.n - vp.s) * 0.12) : 0;
        const padLng = vp ? Math.max(0.02, Math.abs(vp.e - vp.w) * 0.12) : 0;
        const bounded = scope === 'view' && vp
          ? live.filter(poi => poi.lat >= vp.s - padLat && poi.lat <= vp.n + padLat && poi.lng >= vp.w - padLng && poi.lng <= vp.e + padLng)
          : live;
        const visible = bounded.length > 0 ? bounded : live.slice(0, 40);
        const mapPois = mergeOsmPois(visible, onlineSupportPois, onlineFuelPois).slice(0, MAX_ALL_MAP_POIS);
        if (bounded.length === 0 && live.length > 0) setQuickToast('Showing nearest live trail places');
        setPois(mapPois);
        webRef.current?.postMessage(JSON.stringify({ type: 'set_pois', pois: mapPois }));
        setSearchResult({ count: visible.length });
      } catch {
        setSearchResult({ count: trailDiscoveries.length || -1 });
        setQuickToast('Could not refresh live trail discovery');
      } finally {
        setIsSearchingTrails(false);
        setTimeout(() => setQuickToast(''), 2200);
      }
    } else {
      setSearchResult({ count: trailDiscoveries.length });
    }
    setShowDiscoveryPanel(true);
    setShowTrailList(false);
    setMapMoved(false);
    setTimeout(() => setSearchResult(null), 2400);
  }

  function selectTrailFromDiscovery(trail: TrailFeature) {
    setShowDiscoveryPanel(false);
    setShowTrailList(false);
    setShowLayerSheet(false);
    setTimeout(() => openTrailFeature(trail), 180);
  }

  async function getSelectedTrailGeometry(trail: TrailFeature) {
    let geometry = nativeMapRef.current?.getTrailHighlight?.() ?? null;
    if (!geometry?.features?.length) {
      nativeMapRef.current?.highlightTrail(trail.lat, trail.lng, trail.name);
      await new Promise(resolve => setTimeout(resolve, 620));
      geometry = nativeMapRef.current?.getTrailHighlight?.() ?? null;
    }
    return geometry;
  }

  function stateIdForTrailPoint(lat: number, lng: number): string | null {
    for (const [id, state] of Object.entries(US_STATES)) {
      if (lat <= state.n && lat >= state.s && lng <= state.e && lng >= state.w) {
        return id.toLowerCase();
      }
    }
    return null;
  }

  function boundsForTrailCoords(coords: [number, number][], bufferM = 1200) {
    let w = 180, s = 90, e = -180, n = -90;
    for (const [lng, lat] of coords) {
      w = Math.min(w, lng);
      s = Math.min(s, lat);
      e = Math.max(e, lng);
      n = Math.max(n, lat);
    }
    if (w > e || s > n) return null;
    const midLat = (s + n) / 2;
    const latDelta = bufferM / 110_540;
    const lngDelta = bufferM / Math.max(30_000, 111_320 * Math.cos(midLat * Math.PI / 180));
    return [w - lngDelta, s - latDelta, e + lngDelta, n + latDelta];
  }

  async function routeSelectedTrailWithGraph(trail: TrailFeature, coords: [number, number][]) {
    if (Platform.OS !== 'ios') return null;
    const stateId = stateIdForTrailPoint(trail.lat, trail.lng);
    if (!stateId) return null;
    const graphPath = trailRouteGraphLocalPath(stateId);
    const info = await FileSystem.getInfoAsync(graphPath).catch(() => null);
    if (!info?.exists) throw new Error(`${stateId.toUpperCase()} trail routing graph is not downloaded yet`);
    if (((info as any)?.size ?? 0) <= 0) throw new Error(`${stateId.toUpperCase()} trail routing graph is empty`);
    const seed: [number, number] = [trail.lng, trail.lat];
    const hasLine = coords.length >= 2;
    const bounds = hasLine
      ? boundsForTrailCoords(coords, 1800)
      : boundsForTrailCoords([seed], 2500);
    const request = {
      start: hasLine ? coords[0] : seed,
      end: hasLine ? coords[coords.length - 1] : undefined,
      bounds,
      corridorM: hasLine ? 1800 : 2500,
    };
    const raw = await routeTrailGraph(graphPath, JSON.stringify(request));
    const parsed = JSON.parse(raw);
    const routed = Array.isArray(parsed?.coords)
      ? parsed.coords
          .map((pair: any) => [Number(pair?.[0]), Number(pair?.[1])] as [number, number])
          .filter((pair: [number, number]) => Number.isFinite(pair[0]) && Number.isFinite(pair[1]))
      : [];
    return routed.length >= 2 ? routed : null;
  }

  function currentMapCenterCoord(): [number, number] | null {
    const vp = viewportRef.current;
    if (vp) return [(vp.e + vp.w) / 2, (vp.n + vp.s) / 2];
    if (userLoc) return [userLoc.lng, userLoc.lat];
    const first = waypoints[0];
    return first ? [first.lng, first.lat] : null;
  }

  function captureLegFromVisibleGeometry(a: TrailCaptureAnchor, b: TrailCaptureAnchor) {
    const lines = [
      ...trailGeometryLines(a.geometry),
      ...trailGeometryLines(b.geometry),
    ];
    type Edge = { to: string; weight: number; coords: [number, number][] };
    type Snap = { key: string; distanceM: number };
    const nodeCoords = new Map<string, [number, number]>();
    const adjacency = new Map<string, Edge[]>();
    const keyFor = (coord: [number, number]) => `${coord[0].toFixed(5)},${coord[1].toFixed(5)}`;
    const addNode = (coord: [number, number]) => {
      const key = keyFor(coord);
      if (!nodeCoords.has(key)) nodeCoords.set(key, coord);
      if (!adjacency.has(key)) adjacency.set(key, []);
      return key;
    };
    const addEdge = (from: [number, number], to: [number, number], coords: [number, number][], multiplier = 1) => {
      const clean = dedupeTrailCoords(coords);
      if (clean.length < 2) return;
      const fromKey = addNode(from);
      const toKey = addNode(to);
      const weight = Math.max(0.1, trailCoordsDistanceM(clean) * multiplier);
      adjacency.get(fromKey)?.push({ to: toKey, weight, coords: clean });
      adjacency.get(toKey)?.push({ to: fromKey, weight, coords: clean.slice().reverse() });
    };

    const seen = new Set<string>();
    for (const raw of lines) {
      const line = dedupeTrailCoords(raw);
      if (line.length < 2) continue;
      const lineKey = `${line[0][0].toFixed(6)},${line[0][1].toFixed(6)}:${line[line.length - 1][0].toFixed(6)},${line[line.length - 1][1].toFixed(6)}`;
      if (seen.has(lineKey)) continue;
      seen.add(lineKey);
      for (let i = 0; i < line.length - 1; i += 1) {
        addEdge(line[i], line[i + 1], [line[i], line[i + 1]]);
      }
    }

    const nodes = [...nodeCoords.entries()];
    for (let i = 0; i < nodes.length; i += 1) {
      for (let j = i + 1; j < nodes.length; j += 1) {
        const gapM = haversineKm(nodes[i][1][1], nodes[i][1][0], nodes[j][1][1], nodes[j][1][0]) * 1000;
        if (gapM > 0 && gapM <= 34) addEdge(nodes[i][1], nodes[j][1], [nodes[i][1], nodes[j][1]], 2.4);
      }
    }

    const snapPoint = (coord: [number, number]): Snap | null => {
      let best: { projected: [number, number]; distanceM: number; line: [number, number][]; segmentIdx: number } | null = null;
      for (const line of lines) {
        const clean = dedupeTrailCoords(line);
        if (clean.length < 2) continue;
        const snap = projectPointToRouteProgress({ lat: coord[1], lng: coord[0] }, clean);
        if (!snap) continue;
        if (!best || snap.distanceM < best.distanceM) {
          best = { projected: snap.projected, distanceM: snap.distanceM, line: clean, segmentIdx: snap.segmentIdx };
        }
      }
      if (!best || best.distanceM > 150) return null;
      const key = addNode(best.projected);
      const prev = best.line[best.segmentIdx];
      const next = best.line[best.segmentIdx + 1];
      addEdge(best.projected, prev, [best.projected, prev]);
      addEdge(best.projected, next, [best.projected, next]);
      nodeCoords.set(key, best.projected);
      return { key, distanceM: best.distanceM };
    };

    const start = snapPoint(a.coord);
    const end = snapPoint(b.coord);
    if (!start || !end) return null;

    const dist = new Map<string, number>([[start.key, 0]]);
    const prev = new Map<string, { key: string; edge: Edge }>();
    const queue = new Set(adjacency.keys());
    while (queue.size) {
      let current: string | null = null;
      let currentDist = Number.POSITIVE_INFINITY;
      for (const key of queue) {
        const value = dist.get(key) ?? Number.POSITIVE_INFINITY;
        if (value < currentDist) {
          current = key;
          currentDist = value;
        }
      }
      if (!current || currentDist === Number.POSITIVE_INFINITY) break;
      queue.delete(current);
      if (current === end.key) break;
      for (const edge of adjacency.get(current) ?? []) {
        if (!queue.has(edge.to)) continue;
        const nextDist = currentDist + edge.weight;
        if (nextDist < (dist.get(edge.to) ?? Number.POSITIVE_INFINITY)) {
          dist.set(edge.to, nextDist);
          prev.set(edge.to, { key: current, edge });
        }
      }
    }
    if (!prev.has(end.key) && start.key !== end.key) return null;
    const parts: [number, number][][] = [];
    let cursor = end.key;
    while (cursor !== start.key) {
      const item = prev.get(cursor);
      if (!item) return null;
      parts.push(item.edge.coords);
      cursor = item.key;
    }
    const coords = parts.reverse().flatMap((part, idx) => idx === 0 ? part : part.slice(1));
    return dedupeTrailCoords(coords);
  }

  function nearestVisibleTrailSnap(fc: GeoJSON.FeatureCollection, seed: [number, number]) {
    let best: { coord: [number, number]; distanceM: number } | null = null;
    for (const line of trailGeometryLines(fc)) {
      const snap = projectPointToRouteProgress({ lat: seed[1], lng: seed[0] }, line);
      if (!snap) continue;
      if (!best || snap.distanceM < best.distanceM) {
        best = { coord: snap.projected, distanceM: snap.distanceM };
      }
    }
    return best;
  }

  async function fetchMapboxPinnedTrailRoute(pins: [number, number][]) {
    if (!mapboxToken || pins.length < 2) return null;
    if (pins.length > 25) throw new Error('Mapbox can route up to 25 anchors at once. Undo a few pins and try again.');
    const pairs = pins.map(([lng, lat]) => `${lng.toFixed(6)},${lat.toFixed(6)}`);
    const radiuses = pins.map(() => '160').join(';');
    const url = `https://api.mapbox.com/directions/v5/mapbox/walking/${pairs.join(';')}` +
      `?access_token=${encodeURIComponent(mapboxToken)}` +
      '&geometries=geojson&overview=full&steps=true&alternatives=false&continue_straight=false' +
      `&radiuses=${radiuses}`;
    const ctrl = new AbortController();
    const tid = setTimeout(() => ctrl.abort(), 12000);
    const data = await fetch(url, { signal: ctrl.signal }).then(async r => {
      const json = await r.json().catch(() => null);
      if (!r.ok) throw new Error(json?.message ?? `Mapbox trail routing failed (${r.status})`);
      return json;
    }).finally(() => clearTimeout(tid));
    const route = data?.routes?.[0];
    const coords = Array.isArray(route?.geometry?.coordinates)
      ? route.geometry.coordinates
          .map((pair: any) => [Number(pair?.[0]), Number(pair?.[1])] as [number, number])
          .filter((pair: [number, number]) => Number.isFinite(pair[0]) && Number.isFinite(pair[1]))
      : [];
    if (coords.length < 2) throw new Error('Mapbox did not return a trail route for these anchors.');

    const waypointDistances = Array.isArray(data?.waypoints)
      ? data.waypoints.map((wp: any) => Number(wp?.distance)).filter((d: number) => Number.isFinite(d))
      : [];
    const worstSnapM = waypointDistances.length ? Math.max(...waypointDistances) : 0;
    if (worstSnapM > 180) {
      throw new Error(`Mapbox snapped one anchor ${Math.round(worstSnapM)}m away. Drop pins closer to the intended trail.`);
    }
    return {
      coords: dedupeTrailCoords(coords),
      distanceM: Number(route.distance) || trailCoordsDistanceM(coords),
      durationS: Number(route.duration) || Math.max(60, trailCoordsDistanceM(coords) / 1.35),
      snapM: worstSnapM,
    };
  }

  async function fetchGraphHopperPinnedTrailRoute(pins: [number, number][]) {
    if (pins.length < 2) return null;
    if (pins.length > 25) throw new Error('Too many pins for one trail route. Undo a few pins and try again.');
    const url = 'https://tiles.gettrailhead.app/api/graphhopper/route';
    const requestGraphHopperLeg = async (legPins: [number, number][], legIndex: number) => {
      const ctrl = new AbortController();
      const tid = setTimeout(() => ctrl.abort(), 16000);
      const data = await fetch(url, {
        method: 'POST',
        signal: ctrl.signal,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          profile: 'foot',
          points: legPins,
        }),
      }).then(async r => {
        const json = await r.json().catch(() => null);
        if (!r.ok) throw new Error(json?.message ?? json?.error ?? `Could not route segment ${legIndex + 1}`);
        return json;
      }).finally(() => clearTimeout(tid));

      const path = data?.paths?.[0];
      const rawCoords = Array.isArray(path?.points?.coordinates) ? path.points.coordinates : [];
      const coords = rawCoords
        .map((pair: any) => [Number(pair?.[0]), Number(pair?.[1])] as [number, number])
        .filter((pair: [number, number]) => Number.isFinite(pair[0]) && Number.isFinite(pair[1]));
      if (coords.length < 2) throw new Error(`Could not route segment ${legIndex + 1}.`);
      return {
        coords: dedupeTrailCoords(coords),
        distanceM: Number(path?.distance) || trailCoordsDistanceM(coords),
        durationS: Number(path?.time) ? Number(path.time) / 1000 : Math.max(60, trailCoordsDistanceM(coords) / 1.35),
      };
    };

    const maxPointsPerRequest = 5;
    let stitched: [number, number][] = [];
    let distanceM = 0;
    let durationS = 0;
    let start = 0;
    let legIndex = 0;
    while (start < pins.length - 1) {
      const end = Math.min(pins.length, start + maxPointsPerRequest);
      const legPins = pins.slice(start, end);
      const leg = await requestGraphHopperLeg(legPins, legIndex);
      stitched = stitched.concat(stitched.length ? leg.coords.slice(1) : leg.coords);
      distanceM += leg.distanceM;
      durationS += leg.durationS;
      start = end - 1;
      legIndex += 1;
    }
    const coords = dedupeTrailCoords(stitched);
    if (coords.length < 2) throw new Error('Could not build a trail route from those pins.');
    return {
      coords,
      distanceM: distanceM || trailCoordsDistanceM(coords),
      durationS: durationS || Math.max(60, trailCoordsDistanceM(coords) / 1.35),
    };
  }

  async function requestStadiaPinnedTrailRoute(pins: [number, number][], timeoutMs = 18000) {
    if (!STADIA_API_KEY) return null;
    if (pins.length < 2) return null;
    if (pins.length > 50) throw new Error('Too many pins for one trail route. Undo a few pins and try again.');
    const ctrl = new AbortController();
    const tid = setTimeout(() => ctrl.abort(), timeoutMs);
    const locations = pins.map(([lon, lat], index) => ({
      lon,
      lat,
      type: index === 0 || index === pins.length - 1 ? 'break' : 'through',
    }));
    const data = await fetch('https://api.stadiamaps.com/route/v1', {
      method: 'POST',
      signal: ctrl.signal,
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Stadia-Auth ${STADIA_API_KEY}`,
      },
      body: JSON.stringify({
        id: 'trailhead_pinned_route',
        locations,
        costing: 'pedestrian',
        units: 'miles',
        format: 'osrm',
        shape_format: 'polyline6',
        directions_options: { units: 'miles' },
      }),
    }).then(async r => {
      const json = await r.json().catch(() => null);
      if (!r.ok) throw new Error(json?.message ?? json?.error ?? `Could not route these pins (${r.status})`);
      return json;
    }).finally(() => clearTimeout(tid));

    const route = data?.routes?.[0];
    const coords = typeof route?.geometry === 'string'
      ? decodePolyline6(route.geometry)
      : Array.isArray(route?.geometry?.coordinates)
        ? route.geometry.coordinates
            .map((pair: any) => [Number(pair?.[0]), Number(pair?.[1])] as [number, number])
            .filter((pair: [number, number]) => Number.isFinite(pair[0]) && Number.isFinite(pair[1]))
        : Array.isArray(data?.trip?.legs)
          ? data.trip.legs.flatMap((leg: any) => typeof leg?.shape === 'string' ? decodePolyline6(leg.shape) : [])
          : [];
    if (coords.length < 2) throw new Error('Could not build a trail route from those pins.');
    return {
      coords: dedupeTrailCoords(coords),
      distanceM: Number(route?.distance) || Number(data?.trip?.summary?.length) * 1609.344 || trailCoordsDistanceM(coords),
      durationS: Number(route?.duration) || Math.max(60, trailCoordsDistanceM(coords) / 1.35),
    };
  }

  async function fetchStadiaPinnedTrailRoute(pins: [number, number][]) {
    const direct = await requestStadiaPinnedTrailRoute(pins, 18000);
    if (!direct) return null;
    const guideM = trailCoordsDistanceM(pins);
    const routedM = direct.distanceM || trailCoordsDistanceM(direct.coords);
    const ratio = guideM > 25 ? routedM / guideM : 1;
    return {
      ...direct,
      confidence: direct.coords.length >= Math.max(12, pins.length * 4) && ratio >= 0.75 && ratio <= 8 ? 'high' as const : 'medium' as const,
    };
  }

  async function fetchStadiaPinnedTrailRouteByLeg(pins: [number, number][]) {
    if (pins.length < 2) return null;
    const statuses: TrailRouteSegmentStatus[] = [];
    let stitched: [number, number][] = [];
    let distanceM = 0;
    let durationS = 0;
    for (let i = 0; i < pins.length - 1; i += 1) {
      try {
        const leg = await requestStadiaPinnedTrailRoute([pins[i], pins[i + 1]], 11000);
        if (!leg?.coords.length) throw new Error('No geometry returned');
        stitched = stitched.concat(stitched.length ? leg.coords.slice(1) : leg.coords);
        distanceM += leg.distanceM;
        durationS += leg.durationS;
        statuses.push({ label: `${i + 1}-${i + 2}`, status: 'ok', engine: 'Routed' });
      } catch (err: any) {
        statuses.push({ label: `${i + 1}-${i + 2}`, status: 'failed', engine: 'Needs pins', message: err?.message ?? 'Could not route this segment' });
        const error = new Error(`Could not route pins ${i + 1}-${i + 2}. Add another pin on the trail between them.`);
        (error as any).segmentStatuses = statuses;
        throw error;
      }
    }
    const coords = dedupeTrailCoords(stitched);
    if (coords.length < 2) throw new Error('Could not build a trail route from those pins.');
    const guideM = trailCoordsDistanceM(pins);
    const routedM = distanceM || trailCoordsDistanceM(coords);
    const ratio = guideM > 25 ? routedM / guideM : 1;
    return {
      coords,
      distanceM: routedM,
      durationS: durationS || Math.max(60, routedM / 1.35),
      confidence: coords.length >= Math.max(12, pins.length * 4) && ratio >= 0.75 && ratio <= 8 ? 'high' as const : 'medium' as const,
      statuses,
    };
  }

  async function routeTrailGraphPath(coords: [number, number][], corridorM = 900) {
    if (Platform.OS !== 'ios' || coords.length < 2) return null;
    const middle = coords[Math.floor(coords.length / 2)];
    const stateId = stateIdForTrailPoint(middle[1], middle[0]) ?? stateIdForTrailPoint(coords[0][1], coords[0][0]);
    if (!stateId) throw new Error('Trail graph state could not be identified');
    const graphPath = trailRouteGraphLocalPath(stateId);
    const info = await FileSystem.getInfoAsync(graphPath).catch(() => null);
    if (!info?.exists || (((info as any)?.size ?? 0) <= 0)) {
      throw new Error(`${stateId.toUpperCase()} trail routing graph is not downloaded yet`);
    }
    const bounds = boundsForTrailCoords(coords, corridorM);
    const raw = await routeTrailGraph(graphPath, JSON.stringify({
      start: coords[0],
      end: coords[coords.length - 1],
      bounds,
      corridorM,
    }));
    const parsed = JSON.parse(raw);
    const routed = Array.isArray(parsed?.coords)
      ? parsed.coords
          .map((pair: any) => [Number(pair?.[0]), Number(pair?.[1])] as [number, number])
          .filter((pair: [number, number]) => Number.isFinite(pair[0]) && Number.isFinite(pair[1]))
      : [];
    return routed.length >= 2 ? dedupeTrailCoords(routed) : null;
  }

  async function downloadSelectedTrail(trail: TrailFeature) {
    const geometry = await getSelectedTrailGeometry(trail);
    const coords = primaryTrailLine(geometry, [trail.lng, trail.lat]);
    const packGeometry: GeoJSON.FeatureCollection = geometry?.features?.length
      ? geometry
      : {
          type: 'FeatureCollection',
          features: [{
            type: 'Feature',
            geometry: { type: 'Point', coordinates: [trail.lng, trail.lat] },
            properties: { name: trail.name, fallback: true },
          }],
        };
    await saveOfflineTrail({
      id: `trail:${trail.id}`,
      trail: { ...trail, support: { ...trail.support, offlineReady: coords.length >= 2, readinessLabel: coords.length >= 2 ? 'Trail downloaded for offline follow' : 'Download this region for full trail follow' } },
      geometry: packGeometry,
      savedAt: Date.now(),
      source: coords.length >= 2 ? 'highlight' : 'manual',
    });
    addSavedPlace({
      id: `trail:${trail.id}`,
      name: trail.name,
      lat: trail.lat,
      lng: trail.lng,
      icon: 'flag',
      note: coords.length >= 2 ? `Offline trail · ${coords.length} points` : 'Saved trailhead · download region for follow',
      createdAt: Date.now(),
    });
    setSelectedTrail(prev => prev?.id === trail.id
      ? { ...prev, support: { ...prev.support, offlineReady: coords.length >= 2, readinessLabel: coords.length >= 2 ? 'Trail saved for offline follow mode' : 'Trail saved. Download this region for full offline trail routing.' } }
      : prev);
    setQuickToast(coords.length >= 2 ? 'Trail saved for offline follow' : 'Trail saved. Download this region for full offline routing.');
    setTimeout(() => setQuickToast(''), 2600);
  }

  async function isTrailRouteGraphReady(trail: TrailFeature) {
    if (Platform.OS !== 'ios') return false;
    const stateId = stateIdForTrailPoint(trail.lat, trail.lng);
    if (!stateId) return false;
    const info = await FileSystem.getInfoAsync(trailRouteGraphLocalPath(stateId)).catch(() => null);
    return Boolean(info?.exists && (((info as any)?.size ?? 0) > 0));
  }

  function makeTrailRoutePlans(trail: TrailFeature, coords: [number, number][], graphReady: boolean, featureCount: number): TrailRoutePlan[] {
    const clean = dedupeTrailCoords(coords);
    if (clean.length < 2) return [];
    const baseDistance = trailCoordsDistanceM(clean);
    const complex = featureCount > 1 || clean.length > 260;
    const complexWarnings = [
      complex ? 'This trail has multiple branches. Choose the line you want to follow.' : 'Review the line before saving or starting.',
      graphReady ? '' : 'Download this region for better offline follow.',
    ].filter(Boolean);
    const plans: TrailRoutePlan[] = [withTrailElevation({
      id: 'segment',
      title: 'Visible segment',
      subtitle: 'Follow the selected line exactly',
      icon: 'git-commit-outline',
      coords: clean,
      distanceM: baseDistance,
      confidence: graphReady ? 'high' : 'medium',
      warnings: graphReady ? ['Follows the selected trail line.'] : complexWarnings,
      engine: graphReady ? 'Saved offline' : 'Route line',
    })];

    const reversed = clean.slice(0, -1).reverse();
    plans.push(withTrailElevation({
      id: 'out_back',
      title: 'Out and back',
      subtitle: 'Return on the same selected line',
      icon: 'return-down-back-outline',
      coords: [...clean, ...reversed],
      distanceM: baseDistance * 2,
      confidence: 'high',
      warnings: ['Good option for unclear trail systems because it returns on the same confirmed line.'],
      engine: 'Route line',
    }));

    if (trailEndpointDistanceM(clean) <= 350 && clean.length >= 8) {
      plans.push(withTrailElevation({
        id: 'loop',
        title: 'Loop direction',
        subtitle: 'Start and finish on the selected loop',
        icon: 'sync-outline',
        coords: clean,
        distanceM: baseDistance,
        confidence: 'high',
        warnings: ['Loop detected from the selected line. Confirm direction before starting.'],
        engine: 'Route line',
      }));
    }

    plans.push(withTrailElevation({
      id: 'far_end',
      title: 'To far end',
      subtitle: 'One-way to the end of this segment',
      icon: 'flag-outline',
      coords: clean,
      distanceM: baseDistance,
      confidence: complex ? 'low' : 'medium',
      warnings: complexWarnings,
      engine: graphReady ? 'Saved offline' : 'Route line',
    }));

    return plans;
  }

  function routeStepsForTrailPlan(trail: TrailFeature, coords: [number, number][], distanceM: number): RouteStep[] {
    const duration = Math.max(60, distanceM / 1.35);
    const last = coords[coords.length - 1];
    return [
      { type: 'depart', modifier: 'straight', name: trail.name, distance: 0, duration: 0, lat: coords[0][1], lng: coords[0][0] },
      { type: 'continue', modifier: 'straight', name: 'Follow confirmed trail route', distance: distanceM, duration, lat: coords[Math.floor(coords.length / 2)][1], lng: coords[Math.floor(coords.length / 2)][0] },
      { type: 'arrive', modifier: 'straight', name: trail.name, distance: 0, duration: 0, lat: last[1], lng: last[0] },
    ];
  }

  function clearTrailTrace() {
    setTrailTraceMode(false);
    setTrailTraceDraft([]);
    trailTraceDraftRef.current = [];
    setTrailTraceRoute([]);
  }

  function clearTrailRoutePreview() {
    setTrailRouteBuilderOpen(false);
    setSavedTrailRouteOpenId(null);
    setTrailRoutePlans([]);
    setSelectedTrailRoutePlanId(null);
    setTrailRouteBuilderError('');
    setTrailSnapFailureReason('');
    setTrailRouteSegmentStatus([]);
    setTrailTraceRoute([]);
    setTrailTraceDraft([]);
    trailTraceDraftRef.current = [];
    setTrailCapturePins([]);
    setTrailCaptureAnchors([]);
    setTrailPinCaptureMode(false);
    setTrailPinCaptureSeedName('');
    trailAutoBuildCountRef.current = 0;
    if (!navMode) {
      setRouteFromCache(false);
      setRouteDebug('');
      setRouteSteps([]);
      setRouteLegs([]);
      setLastRouteCoords([]);
      setIsRouted(false);
      setRouteProgress(null);
      nativeMapRef.current?.resetRoute();
      webRef.current?.postMessage(JSON.stringify({ type: 'nav_reset' }));
    }
  }

  function closeTrailRouteBuilderPanel() {
    if (savedTrailRouteOpenId && selectedTrail && trailRoutePlans.length > 0) {
      setTrailRouteBuilderOpen(false);
      setTrailCardCollapsed(true);
      setTrailPinCaptureMode(false);
      return;
    }
    clearTrailRoutePreview();
    setTrailCardCollapsed(false);
  }

  function reopenSavedTrailRouteBuilder() {
    if (!savedTrailRouteOpenId || !selectedTrail) {
      setTrailCardCollapsed(false);
      return;
    }
    const plan = trailRoutePlans.find(p => p.id === selectedTrailRoutePlanId) ?? trailRoutePlans[0];
    if (!plan) {
      setTrailCardCollapsed(false);
      return;
    }
    setTrailCardCollapsed(true);
    setTrailRouteBuilderOpen(true);
    setSelectedTrailRoutePlanId(plan.id);
    previewTrailRoutePlan(selectedTrail, plan);
  }

  function beginTrailTrace() {
    if (navMode) return;
    setSavedTrailRouteOpenId(null);
    setSelectedCamp(null);
    setSelectedCommunityPin(null);
    setTappedPoi(null);
    setTappedGas(null);
    setTappedTileSpot(null);
    setTappedTrail(null);
    setTrailCardCollapsed(false);
    setTrailRouteBuilderOpen(false);
    setTrailRoutePlans([]);
    setSelectedTrailRoutePlanId(null);
    setTrailRouteBuilderError('');
    setTrailSnapFailureReason('');
    setTrailRouteSegmentStatus([]);
    setTrailTraceDraft([]);
    trailTraceDraftRef.current = [];
    setTrailTraceRoute([]);
    setTrailTraceMode(true);
    setQuickToast('Trace a trail with your finger');
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light).catch(() => {});
    setTimeout(() => setQuickToast(''), 2200);
  }

  function appendTrailTracePoint(coord: [number, number], reset = false) {
    setTrailTraceDraft(prev => {
      const base = reset ? [] : prev;
      const last = base[base.length - 1];
      if (last && haversineKm(last[1], last[0], coord[1], coord[0]) * 1000 < 8) return base;
      const next = [...base, coord].slice(-900);
      trailTraceDraftRef.current = next;
      return next;
    });
  }

  async function routeTraceWithGraph(coords: [number, number][]) {
    if (trailSnapMode === 'straight') return null;
    return routeTrailGraphPath(coords, 900);
  }

  async function finishTrailTrace() {
    setTrailTraceMode(false);
    const rough = simplifyTrailTrace(trailTraceDraftRef.current);
    if (rough.length < 2) {
      setQuickToast('Trace was too short');
      setTimeout(() => setQuickToast(''), 2200);
      return;
    }

    setTrailRouteBuilding(true);
    setTrailRouteBuilderOpen(true);
    setTrailCardCollapsed(true);
    setTrailRouteBuilderError('');
    setTrailSnapFailureReason('');
    setQuickToast('Building route from trace...');

    let captured = rough;
    let graphSnapped = false;
    try {
      const graphRoute = await routeTraceWithGraph(rough);
      if (graphRoute?.length) {
        captured = graphRoute;
        graphSnapped = true;
      } else if (trailSnapMode !== 'straight') {
        setTrailSnapFailureReason('Trail graph did not match that trace. Keeping the drawn line.');
      }
    } catch (err: any) {
      const message = normalizeTrailSnapFailure(err, trailSnapMode);
      setTrailRouteBuilderError(message);
      setTrailSnapFailureReason(message);
    }

    const distanceM = trailCoordsDistanceM(captured);
    const midpoint = captured[Math.floor(captured.length / 2)];
    const feature: TrailFeature = {
      id: `captured:${Date.now()}`,
      name: graphSnapped ? 'Captured trail route' : 'Drawn trail route',
      subtitle: `${fmtTrailRouteDistance(distanceM)} · ${fmtTrailRouteTime(distanceM)} · ${graphSnapped ? 'trail line' : 'drawn line'}`,
      type: 'trail',
      source: 'trip',
      lat: midpoint[1],
      lng: midpoint[0],
      score: graphSnapped ? 100 : 55,
      support: buildTrailSupport(
        { lat: midpoint[1], lng: midpoint[0] },
        trailSupportCamps,
        trailSupportFuel,
        allMapPois,
        mapReports,
        offlineSaved,
      ),
    };
      const plan: TrailRoutePlan = withTrailElevation({
        id: 'capture',
        title: graphSnapped ? 'Captured trail route' : 'Drawn trail route',
        subtitle: `Trace route · ${fmtTrailElevation(estimateTrailElevation(captured))}`,
        icon: graphSnapped ? 'git-branch-outline' : 'analytics-outline',
        coords: captured,
        distanceM,
        confidence: graphSnapped ? 'high' : 'low',
        warnings: [graphSnapped
          ? 'Built from the trail line inside your traced area.'
          : 'Drawn by hand. Add pins at bends and forks for a cleaner route.'],
        engine: graphSnapped ? 'Trail line' : 'Drawn line',
      });
    setSelectedTrail(feature);
    setTrailTraceDraft(rough);
    trailTraceDraftRef.current = rough;
    setTrailTraceRoute(captured);
    setTrailRoutePlans([plan]);
    setSelectedTrailRoutePlanId('capture');
    setTrailRouteBuilderError(prev => graphSnapped ? '' : prev);
    setTrailRouteBuilding(false);
    setQuickToast('');
    previewTrailRoutePlan(feature, plan);
    Haptics.notificationAsync(graphSnapped ? Haptics.NotificationFeedbackType.Success : Haptics.NotificationFeedbackType.Warning).catch(() => {});
  }

