  async function seedTrailPinCaptureFromTrail(trail: TrailFeature, geometry?: GeoJSON.FeatureCollection | null) {
    if (navMode) return;
    const seedRaw: [number, number] = [trail.lng, trail.lat];
    let seedGeometry = geometry?.features?.length ? geometry : null;
    if (!seedGeometry) {
      seedGeometry = await nativeMapRef.current?.captureTrailAt?.(trail.lat, trail.lng, trail.name).catch(() => null) ?? null;
    }
    const snap = seedGeometry ? nearestVisibleTrailSnap(seedGeometry, seedRaw) : null;
    const seed = seedGeometry?.features?.length && snap && snap.distanceM <= 240 ? snap.coord : seedRaw;
    const anchorGeometry = seedGeometry?.features?.length
      ? seedGeometry
      : { type: 'FeatureCollection' as const, features: [] };
    const anchor: TrailCaptureAnchor = { coord: seed, geometry: anchorGeometry };
    setSelectedCamp(null);
    setSelectedCommunityPin(null);
    setTappedPoi(null);
    setTappedGas(null);
    setTappedTileSpot(null);
    setTappedTrail(null);
    setSelectedTrail(null);
    setTrailCardCollapsed(false);
    setTrailRouteBuilderOpen(false);
    setTrailRoutePlans([]);
    setSelectedTrailRoutePlanId(null);
    setTrailRouteBuilderError('');
    setTrailSnapFailureReason('');
    setTrailBuildFinalized(false);
    setTrailTraceMode(false);
    setTrailTraceRoute([]);
    setTrailCaptureAnchors([anchor]);
    trailAutoBuildCountRef.current = 0;
    setTrailCapturePins([seed]);
    setTrailPinCaptureSeedName(trail.name);
    setTrailTraceDraft([seed]);
    trailTraceDraftRef.current = [seed];
    setTrailPinCaptureMode(true);
    setQuickToast(snap && snap.distanceM <= 240
      ? 'Start snapped. Tap bends, forks, and finish.'
      : 'Start set. Tap bends, forks, and finish.');
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light).catch(() => {});
    setTimeout(() => setQuickToast(''), 3600);
  }

  async function addTrailCaptureAnchor(rawCoord: [number, number]) {
    if (trailCaptureBusy) return;
    if (!rawCoord) {
      setQuickToast('Tap near the trail first');
      setTimeout(() => setQuickToast(''), 2400);
      return;
    }
    setTrailCaptureBusy(true);
    try {
      setTrailBuildFinalized(false);
      const geometry = await nativeMapRef.current?.captureTrailAt?.(rawCoord[1], rawCoord[0], trailPinCaptureSeedName || undefined);
      const snap = geometry ? nearestVisibleTrailSnap(geometry, rawCoord) : null;
      const snapped = geometry?.features?.length && snap && snap.distanceM <= 180 ? snap.coord : rawCoord;
      const anchorGeometry = geometry?.features?.length ? geometry : { type: 'FeatureCollection' as const, features: [] };
      const last = trailCaptureAnchors[trailCaptureAnchors.length - 1]?.coord;
      if (last && haversineKm(last[1], last[0], snapped[1], snapped[0]) * 1000 < 12) {
        setQuickToast('That point is already on the route');
        setTimeout(() => setQuickToast(''), 1800);
        return;
      }
      const nextAnchors = [...trailCaptureAnchors, { coord: snapped, geometry: anchorGeometry }].slice(-24);
      const pins = nextAnchors.map(anchor => anchor.coord);
      setTrailCaptureAnchors(nextAnchors);
      setTrailCapturePins(pins);
      setTrailTraceDraft([]);
      trailTraceDraftRef.current = [];
      setTrailTraceRoute([]);
      if (nextAnchors.length >= 2) {
        trailAutoBuildCountRef.current += 1;
        setQuickToast('Building route...');
        await capturePinnedTrailRoute(nextAnchors, { previewOnly: true });
      } else if (!geometry?.features?.length || !snap || snap.distanceM > 180) {
        setQuickToast('Start set. Tap the next trail point.');
        setTimeout(() => setQuickToast(''), 2600);
      } else {
        setQuickToast('Start snapped. Tap the next trail point.');
        setTimeout(() => setQuickToast(''), 2200);
      }
      Haptics.selectionAsync().catch(() => {});
    } finally {
      setTrailCaptureBusy(false);
    }
  }

  function undoTrailCapturePin() {
    let nextAnchors: TrailCaptureAnchor[] = [];
    setTrailBuildFinalized(false);
    setTrailCaptureAnchors(prev => {
      const next = prev.slice(0, -1);
      nextAnchors = next;
      const pins = next.map(anchor => anchor.coord);
      setTrailCapturePins(pins);
      setTrailTraceDraft([]);
      trailTraceDraftRef.current = [];
      return next;
    });
    setTrailTraceRoute([]);
    if (nextAnchors.length >= 2) {
      setTimeout(() => capturePinnedTrailRoute(nextAnchors, { previewOnly: true }), 0);
    }
  }

  async function capturePinnedTrailRoute(anchorOverride?: TrailCaptureAnchor[], opts: { previewOnly?: boolean } = {}) {
    if (trailCaptureBusy && !anchorOverride) return;
    const previewOnly = !!opts.previewOnly;
    const anchors = anchorOverride ?? trailCaptureAnchors;
    const pins = anchors.map(anchor => anchor.coord);
    if (anchors.length < 2) {
      setQuickToast('Drop at least start and finish pins');
      setTimeout(() => setQuickToast(''), 2400);
      return;
    }

    setTrailCaptureBusy(true);
    if (!previewOnly) {
      setTrailRouteBuilding(true);
      setTrailRouteBuilderOpen(false);
      setTrailCardCollapsed(true);
      setTrailBuildFinalized(false);
    }
    setTrailRouteBuilderError('');
    setTrailSnapFailureReason('');
    setTrailRouteSegmentStatus(pins.slice(0, -1).map((_, idx) => ({ label: `${idx + 1}-${idx + 2}`, status: 'fallback', engine: 'Queued' })));
    setQuickToast(previewOnly ? 'Building route...' : 'Building trail route...');

    try {
      let clean: [number, number][] = [];
      let engineLabel = 'Trail route';
      let engineWarning = 'Built from your pins. Review the line before saving.';
      let engineConfidence: TrailRoutePlan['confidence'] = 'high';
      let segmentStatuses: TrailRouteSegmentStatus[] = [];
      let routedDistanceM = 0;
      if (trailSnapMode === 'straight') {
        clean = dedupeTrailCoords(pins);
        routedDistanceM = trailCoordsDistanceM(clean);
        engineLabel = 'Straight line';
        engineConfidence = 'low';
        segmentStatuses = pins.slice(0, -1).map((_, idx) => ({
          label: `${idx + 1}-${idx + 2}`,
          status: 'fallback',
          engine: 'Straight',
          message: 'Manual connector',
        }));
        engineWarning = trailSnapModeHelp('straight');
      } else {
        try {
        const stadiaRoute = pins.length > 2
          ? await fetchStadiaPinnedTrailRouteByLeg(pins)
          : await fetchStadiaPinnedTrailRoute(pins);
        if (!stadiaRoute) throw new Error('Trail route unavailable.');
        clean = stadiaRoute.coords;
        routedDistanceM = stadiaRoute.distanceM;
        engineConfidence = stadiaRoute.confidence;
        segmentStatuses = 'statuses' in stadiaRoute && Array.isArray((stadiaRoute as any).statuses)
          ? (stadiaRoute as any).statuses as TrailRouteSegmentStatus[]
          : [{ label: '1-2', status: 'ok', engine: 'Routed' }];
      } catch (stadiaErr: any) {
        if (Array.isArray(stadiaErr?.segmentStatuses)) {
          segmentStatuses = stadiaErr.segmentStatuses;
          setTrailRouteSegmentStatus(segmentStatuses);
        }
        try {
          const graphHopperRoute = await fetchGraphHopperPinnedTrailRoute(pins);
          if (!graphHopperRoute) throw new Error('Trail route unavailable.');
          clean = graphHopperRoute.coords;
          routedDistanceM = graphHopperRoute.distanceM;
          engineLabel = 'Trail route';
          engineConfidence = 'medium';
          segmentStatuses = pins.slice(0, -1).map((_, idx) => ({
            label: `${idx + 1}-${idx + 2}`,
            status: idx < segmentStatuses.length && segmentStatuses[idx].status === 'failed' ? 'fallback' : 'ok',
            engine: 'Adjusted',
          }));
          engineWarning = 'Built with an adjusted route pass. Review the line before saving.';
        } catch (graphHopperErr: any) {
          try {
            const mapboxRoute = await fetchMapboxPinnedTrailRoute(pins);
            if (!mapboxRoute) throw new Error('Mapbox token is not ready yet.');
            clean = mapboxRoute.coords;
            routedDistanceM = mapboxRoute.distanceM;
            engineLabel = 'Trail route';
            engineConfidence = 'low';
            segmentStatuses = pins.slice(0, -1).map((_, idx) => ({
              label: `${idx + 1}-${idx + 2}`,
              status: idx < segmentStatuses.length && segmentStatuses[idx].status === 'failed' ? 'fallback' : 'ok',
              engine: 'Adjusted',
            }));
            engineWarning = 'Add pins at tight bends if the line cuts corners.';
          } catch (mapboxErr: any) {
            const captured: [number, number][] = [];
            const localStatuses: TrailRouteSegmentStatus[] = [];
            for (let i = 0; i < anchors.length - 1; i += 1) {
              const segment = captureLegFromVisibleGeometry(anchors[i], anchors[i + 1]);
              if (!segment?.length) {
                localStatuses.push({ label: `${i + 1}-${i + 2}`, status: 'failed', engine: 'Needs pins', message: 'No visible trail connection found' });
                setTrailRouteSegmentStatus(localStatuses);
                throw new Error(`Could not connect pins ${i + 1} and ${i + 2}. Add another pin on the trail between them.`);
              }
              captured.push(...(captured.length ? segment.slice(1) : segment));
              localStatuses.push({ label: `${i + 1}-${i + 2}`, status: 'fallback', engine: 'Map line' });
            }
            clean = dedupeTrailCoords(captured);
            routedDistanceM = trailCoordsDistanceM(clean);
            engineLabel = 'Trail route';
            engineConfidence = 'low';
            segmentStatuses = localStatuses;
            engineWarning = 'Add pins around curves if the line cuts corners.';
          }
        }
      }
      }
      if (clean.length < 2) throw new Error('Pinned capture returned an empty route.');

      const distanceM = routedDistanceM || trailCoordsDistanceM(clean);
      const midpoint = clean[Math.floor(clean.length / 2)];
      const feature: TrailFeature = {
        id: `pinned:${Date.now()}`,
        name: 'Pinned trail route',
        subtitle: `${fmtTrailRouteDistance(distanceM)} · ${fmtTrailRouteTime(distanceM)} · pinned route`,
        type: 'trail',
        source: 'trip',
        lat: midpoint[1],
        lng: midpoint[0],
        score: 100,
        support: buildTrailSupport(
          { lat: midpoint[1], lng: midpoint[0] },
          trailSupportCamps,
          trailSupportFuel,
          allMapPois,
          mapReports,
          offlineSaved,
        ),
      };
      const plan: TrailRoutePlan = withTrailElevation({
        id: 'capture',
        title: 'Pinned trail route',
        subtitle: `${fmtTrailRouteDistance(distanceM)} · ${pins.length} points · ${fmtTrailElevation(estimateTrailElevation(clean))}`,
        icon: 'git-branch-outline',
        coords: clean,
        distanceM,
        confidence: engineConfidence,
        warnings: [engineWarning],
        engine: engineLabel,
      });
      if (!previewOnly) setSelectedTrail(feature);
      if (previewOnly) {
        setTrailTraceDraft([]);
        trailTraceDraftRef.current = [];
      } else {
        setTrailTraceDraft([]);
        trailTraceDraftRef.current = [];
      }
      setTrailTraceRoute(clean);
      setTrailRoutePlans([plan]);
      setSelectedTrailRoutePlanId('capture');
      setTrailRouteBuilderError('');
      setTrailSnapFailureReason('');
      setTrailRouteSegmentStatus(segmentStatuses);
      hydrateTrailRoutePlanElevation(plan);
      if (previewOnly) {
        setQuickToast('Preview snapped. Add another point or tap BUILD.');
        setTimeout(() => setQuickToast(''), 2600);
      } else {
        setTrailBuildFinalized(true);
        setQuickToast('Route ready. Save it or start following.');
        setTimeout(() => setQuickToast(''), 2600);
        previewTrailRoutePlan(feature, plan);
        Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success).catch(() => {});
      }
    } catch (err: any) {
      const message = normalizeTrailSnapFailure(err, trailSnapMode);
      setTrailRouteBuilderError(message);
      setTrailSnapFailureReason(message);
      setQuickToast(message);
      setTimeout(() => setQuickToast(''), 5200);
      if (!previewOnly) Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error).catch(() => {});
    } finally {
      setTrailCaptureBusy(false);
      setTrailRouteBuilding(false);
    }
  }

  function previewTrailRoutePlan(trail: TrailFeature, plan: TrailRoutePlan) {
    const steps = routeStepsForTrailPlan(trail, plan.coords, plan.distanceM);
    setRouteFromCache(true);
    setRouteDebug(`trail route preview: ${plan.title}`);
    setRouteSteps(steps);
    setRouteLegs([steps]);
    setLastRouteCoords(plan.coords);
    setIsRouted(true);
    nativeMapRef.current?.restoreRoute(plan.coords, steps, [steps], plan.distanceM, Math.max(60, plan.distanceM / 1.35));
  }

  function trailRoutePlanStatus(plan: TrailRoutePlan) {
    if (plan.confidence === 'high') return { label: 'READY', color: C.orange, icon: 'checkmark-circle-outline' as const };
    if (plan.confidence === 'medium') return { label: 'CHECK LINE', color: C.yellow, icon: 'eye-outline' as const };
    return { label: 'ADD PINS', color: C.red, icon: 'add-circle-outline' as const };
  }

  async function hydrateTrailRoutePlanElevation(plan: TrailRoutePlan) {
    if (plan.elevationConfidence && plan.elevationConfidence !== 'unavailable') return;
    try {
      const elevation = await sampleTrailElevationFromSrtm(plan.coords);
      if (elevation.elevationConfidence === 'unavailable') return;
      setTrailRoutePlans(prev => prev.map(item => item.id === plan.id ? { ...item, ...elevation } : item));
    } catch {
      // Elevation is optional; route distance/time remain authoritative.
    }
  }

  async function openTrailRouteBuilder(trail: TrailFeature) {
    await seedTrailPinCaptureFromTrail(trail);
  }

  function startTrailRoutePlan(trail: TrailFeature, plan: TrailRoutePlan) {
    const steps = routeStepsForTrailPlan(trail, plan.coords, plan.distanceM);
    const duration = Math.max(60, plan.distanceM / 1.35);
    const last = plan.coords[plan.coords.length - 1];
    if (navMode) endNavigation();
    setRouteProgress(null);
    setRouteFromCache(true);
    setRouteDebug(`confirmed trail follow: ${plan.title}`);
    setRouteSteps(steps);
    setRouteLegs([steps]);
    setLastRouteCoords(plan.coords);
    setIsRouted(true);
    navDestRef.current = { lat: last[1], lng: last[0], name: trail.name, day: 0, type: 'trail' };
    setNavDest(navDestRef.current);
    nativeMapRef.current?.restoreRoute(plan.coords, steps, [steps], plan.distanceM, duration);
    setSelectedTrail(null);
    setTrailRouteBuilderOpen(false);
    setTrailCardCollapsed(false);
    setNavMode(true);
    focusNavigationCamera();
  }

  async function saveTrailRoutePlan(trail: TrailFeature, plan: TrailRoutePlan, nameOverride?: string) {
    if (plan.coords.length < 2) return;
    const routeName = (nameOverride || trail.name || 'Pinned trail route').trim() || 'Pinned trail route';
    const namedTrail = { ...trail, name: routeName };
    await saveOfflineTrail({
      id: `captured:${namedTrail.id}`,
      trail: {
        ...namedTrail,
        support: {
          ...namedTrail.support,
          offlineReady: true,
          readinessLabel: 'Captured route saved for offline follow',
        },
      },
      geometry: {
        type: 'FeatureCollection',
        features: [{
          type: 'Feature',
          geometry: { type: 'LineString', coordinates: plan.coords },
          properties: {
            name: routeName,
            route_name: routeName,
            captured: true,
            distance_m: Math.round(plan.distanceM),
            elevation_gain_ft: plan.elevationGainFt,
            elevation_loss_ft: plan.elevationLossFt,
            elevation_confidence: plan.elevationConfidence ?? 'unavailable',
          },
        }],
      },
      savedAt: Date.now(),
      source: 'manual',
    });
    addSavedPlace({
      id: `captured:${namedTrail.id}`,
      name: routeName,
      lat: namedTrail.lat,
      lng: namedTrail.lng,
      icon: 'flag',
      note: `${fmtTrailRouteDistance(plan.distanceM)} · ${fmtTrailElevation(plan)} captured trail route`,
      createdAt: Date.now(),
    });
    setQuickToast('Saved to Route Builder > Trails');
    Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success).catch(() => {});
    setTimeout(() => setQuickToast(''), 2400);
  }

  function nameAndSaveTrailRoutePlan(trail: TrailFeature, plan: TrailRoutePlan) {
    const fallbackName = trail.name === 'Pinned trail route' ? 'Pinned trail route' : trail.name;
    if (Platform.OS === 'ios' && typeof Alert.prompt === 'function') {
      Alert.prompt(
        'Name trail route',
        'Saved routes are cached for offline follow.',
        [
          { text: 'Cancel', style: 'cancel' },
          { text: 'Save', onPress: (name?: string) => saveTrailRoutePlan(trail, plan, name || fallbackName) },
        ],
        'plain-text',
        fallbackName,
      );
      return;
    }
    saveTrailRoutePlan(trail, plan, fallbackName);
  }

  function openExternalMaps(lat: number, lng: number, name: string) {
    const label = encodeURIComponent(name);
    const choices: any[] = [
      { text: 'Navigate in App', onPress: () => navigateToCamp({ lat, lng, name }) },
      { text: 'Google Maps', onPress: () => Linking.openURL(`https://www.google.com/maps/dir/?api=1&destination=${lat},${lng}&travelmode=driving`) },
      { text: 'Waze', onPress: () => Linking.openURL(`waze://?ll=${lat},${lng}&navigate=yes`) },
      { text: 'Cancel', style: 'cancel' },
    ];
    if (Platform.OS === 'ios') {
      choices.splice(2, 0, { text: 'Apple Maps', onPress: () => Linking.openURL(`maps://?daddr=${lat},${lng}&q=${label}`) });
    }
    Alert.alert('Get Directions', name.split(',')[0], choices);
  }

