const DARK_OVR = {
  bg:      'rgba(5,5,5,0.72)',
  bg2:     'rgba(5,5,5,0.82)',
  border:  'rgba(255,255,255,0.09)',
  border2: 'rgba(255,255,255,0.055)',
  text:    '#F5F5F7',
  text2:   '#C7C9CC',
  text3:   '#8A8A92',
};

const LIGHT_OVR = {
  bg:      'rgba(250,247,242,0.96)',
  bg2:     'rgba(244,240,235,0.98)',
  border:  '#d1c7b8',
  border2: '#ebe4dc',
  text:    '#1a1208',
  text2:   '#5a4e3e',
  text3:   '#8a7a68',
};

function overlayPalette(C: ColorPalette) {
  const bg = String(C.bg || '').toLowerCase();
  return bg.includes('f7') || bg.includes('fff') || bg.includes('250') ? LIGHT_OVR : DARK_OVR;
}

